  'weifang/dragon': ('ว่าวมังกร', 'ว่าวมังกรขนาดยาวกว่าร้อยเมตรเป็นไฮไลท์สำคัญของเทศกาลว่าว'),
  'weifang/radish': ('หัวไชเท้าเวยฟาง', 'หัวไชเท้าสีเขียวที่สามารถรับประทานสดได้เหมือนผลไม้ถือเป็นของดีขึ้นชื่อของเมือง'),
  'dezhou/chicken': ('ไก่ตุ๋นเต๋อโจว', 'ไก่ตุ๋นเนื้อนุ่มจนหลุดจากกระดูกเมนูนี้เคยเป็นอาหารที่ถวายแด่จักรพรรดิในสมัยก่อน'),
  'dezhou/sun': ('หุบเขาพลังงานแสงอาทิตย์', 'ที่นี่เป็นที่ตั้งของหนึ่งในศูนย์กลางพลังงานแสงอาทิตย์ที่ใหญ่ที่สุดในโลก'),
  'dezhou/grapes': ('แหล่งปลูกแตงและองุ่น', 'ที่ราบอันอุดมสมบูรณ์แห่งนี้เต็มไปด้วยแตงและองุ่นมากมายในช่วงฤดูร้อน'),
  'dezhou/train': ('ท่าเรือคลองขุด', 'ในอดีตที่นี่เคยเป็นท่าเรือขนส่งธัญพืชที่คึกคักที่สุดแห่งหนึ่งในยุคคลองต้ายวิ่นเหอ'),
  'xuzhou/stone': ('ภาพสลักหินสมัยราชวงศ์ฮั่น', 'แผ่นหินจากสุสานสมัยราชวงศ์ฮั่นช่วยถ่ายทอดภาพวิถีชีวิตของผู้คนเมื่อ 2,000 ปีก่อน'),
  'xuzhou/terracotta': ('กองทัพทหารดินเผา', 'มีการขุดพบกองทัพทหารดินเผาที่มีขนาดเล็กกว่าแต่เก่าแก่กว่าที่นี่'),
  'xuzhou/lake': ('ทะเลสาบอวิ๋นหลง', 'พื้นที่ริมทะเลสาบอวิ๋นหลงเปรียบเสมือนปอดสีเขียวของเมืองนี้'),
  'xuzhou/skewer': ('วัฒนธรรมปิ้งย่าง', 'เมืองนี้ได้ชื่อว่าเป็นเมืองหลวงแห่งปิ้งย่างของจีน โดยมีเนื้อแกะเสียบไม้ย่างบนเตาถ่านตลอดทั้งคืน'),
  'zhenjiang/vinegar': ('น้ำส้มสายชูดำเจิ้นเจียง', 'น้ำส้มสายชูข้าวหมักที่มีชื่อเสียงที่สุดของจีนแห่งนี้มีประวัติการหมักบ่มมายาวนานกว่า 1,400 ปี'),
  'zhenjiang/temple': ('วัดจินซาน', 'วัดที่เป็นฉากในตำนานนางพญางูขาวแห่งนี้ตั้งตระหง่านอยู่ริมแม่น้ำ'),
  'zhenjiang/pot': ('บะหมี่ฝาหม้อ', 'บะหมี่ฝาหม้อที่ปรุงด้วยการวางฝาหม้อลอยไว้บนน้ำซุปเป็นเมนูอาหารเช้าขึ้นชื่อของท้องถิ่น'),
  'zhenjiang/bridge': ('ริมฝั่งแม่น้ำแยงซี', 'พื้นที่ริมแม่น้ำบริเวณสามขุนเขาแห่งนี้รายล้อมไปด้วยสวนสาธารณะสำหรับเดินเล่น'),
  'jiaxing/zongzi': ('บ๊ะจ่าง', 'ที่นี่คือเมืองหลวงแห่งบ๊ะจ่างหรือข้าวเหนียวห่อใบไผ่ที่มีชื่อเสียง'),
  'jiaxing/boat': ('เรือแดงแห่งทะเลสาบหนานหู', 'ในปี ค.ศ. 1921 การประชุมสมัชชาพรรคครั้งแรกได้จัดขึ้นบนเรือลำหนึ่งในทะเลสาบแห่งนี้'),
  'jiaxing/silk': ('เมืองแห่งผ้าไหม', 'ผ้าไหมเจียงหนานถูกทอขึ้นในเมืองริมคลองแห่งนี้มานานหลายศตวรรษ'),
  'jiaxing/canal': ('เมืองน้ำอูเจิ้น', 'สัมผัสบรรยากาศเมืองริมน้ำที่มีสะพานหินและโคมไฟประดับประดาด้วยการล่องเรือ'),
  'lishui/mountains': ('ยอดเขาสีเขียว', 'พื้นที่ที่เต็มไปด้วยภูเขามากที่สุดในเจ้อเจียง ซึ่งมีหมู่บ้านบนนาขั้นบันไดตั้งอยู่ท่ามกลางหมู่เมฆ'),
  'lishui/camera': ('สวรรค์ของช่างภาพ', 'นาขั้นบันไดท่ามกลางสายหมอกเป็นหนึ่งในทิวทัศน์ที่ถูกถ่ายภาพมากที่สุดในจีน'),
  'lishui/mushroom': ('ดินแดนแห่งเห็ด', 'อำเภอชิงหยวนถือเป็นแหล่งกำเนิดการเพาะเห็ดที่สำคัญที่สุดของโลก'),
  'lishui/raft': ('ล่องแพไม้ไผ่', 'ล่องแพไม้ไผ่ไปตามแม่น้ำโอวเจียงเพื่อชมความงามของหุบเขาเขียวขจี'),
  'anqing/opera': ('งิ้วหวงเหมย', 'ศิลปะการแสดงงิ้วท้องถิ่นที่เป็นที่รักมากที่สุดของจีนมีต้นกำเนิดมาจากดินแดนแห่งนี้'),
  'anqing/pagoda': ('เจดีย์เจิ้นเฟิง', 'เจดีย์เก่าแก่อายุกว่า 400 ปีริมแม่น้ำแยงซีที่ได้รับการขนานนามว่าเป็นประภาคารแห่งแรกของแม่น้ำ'),
  'anqing/tea': ('ชาเยว่ซี', 'ชาเขียวรสเลิศที่มีกลิ่นหอมละมุนปลูกอยู่บนไหล่เขาต้าเปี๋ย'),
  'anqing/sail': ('ประตูแม่น้ำ', 'เมืองท่าสำคัญริมแม่น้ำแยงซีในมณฑลอันฮุย ซึ่งชื่อเมืองมีความหมายว่าการเฉลิมฉลองอย่างสันติ'),
  'ganzhou/orange': ('ส้มนาเวลก้านหนาน', 'ส้มนาเวลที่ขึ้นชื่อว่าหวานที่สุดในจีนเติบโตได้ดีในดินสีแดงของที่นี่'),
  'ganzhou/house': ('บ้านดินชาวฮากกา', 'วัฒนธรรมชาวฮากกาสืบทอดมายาวนานหลายศตวรรษภายในบ้านทรงกลมที่สร้างเหมือนป้อมปราการ'),
  'ganzhou/pavilion': ('ศาลาอวี้กู', 'ศาลาที่กวีสมัยราชวงศ์ซ่งเคยแต่งบทกลอนถึง ซึ่งตั้งอยู่บนจุดที่แม่น้ำสองสายมาบรรจบกัน'),
  'ganzhou/star': ('การเดินทัพทางไกล', 'เมืองนี้เป็นจุดเริ่มต้นของการเดินทัพทางไกลของกองทัพแดง'),
  'putian/shrine': ('ศาลเจ้าแม่หม่าโจ้ว', 'เจ้าแม่หม่าโจ้วเทพีผู้คุ้มครองชาวเรือประสูติที่นี่ และศาลเจ้าหลักของท่านตั้งอยู่บนเกาะเหมยโจว'),
  'putian/lychee': ('สวนลิ้นจี่', 'ต้นลิ้นจี่อายุกว่าพันปีทำให้เมืองนี้ได้รับฉายาว่าเป็นดินแดนแห่งลิ้นจี่'),
  'putian/shoe': ('เมืองหลวงแห่งรองเท้า', 'สัดส่วนการผลิตรองเท้ากีฬาจำนวนมหาศาลของโลกมาจากโรงงานในเมืองนี้'),
  'putian/wave': ('เกาะเหมยโจว', 'เกาะที่เดินทางไปถึงได้ด้วยเรือเฟอร์รี่แห่งนี้มีชื่อเสียงในเรื่องชายหาดและเทศกาลงานวัด'),
  'mudanjiang/snow': ('หมู่บ้านหิมะ', 'หมู่บ้านในเทพนิยายที่ถูกปกคลุมด้วยหิมะหนานุ่มและส่องประกายงดงามในฤดูหนาว'),
  'mudanjiang/lake': ('ทะเลสาบจิ้งปัว', 'ทะเลสาบที่เกิดจากการระเบิดของภูเขาไฟซึ่งมีน้ำตกเตี้ยวสุ่ยโหลวที่ยังคงไหลแม้ในฤดูหนาว'),
  'mudanjiang/tiger': ('สวนเสือไซบีเรีย', 'หนึ่งในเขตรักษาพันธุ์เสือไซบีเรียที่ใหญ่ที่สุดในโลก'),
  'mudanjiang/ski': ('ฤดูกาลเล่นสกี', 'ฤดูหนาวที่มีหิมะตกยาวนานทำให้ภูมิภาคนี้เป็นจุดหมายปลายทางของนักสกีทุกคน'),
  'changzhou/dino': ('สวนสนุกไดโนเสาร์', 'สวนสนุกธีมไดโนเสาร์ที่มีชื่อเสียงที่สุดของจีนและเป็นสัญลักษณ์สำหรับครอบครัวของเมืองนี้'),
  'changzhou/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์ที่สูงที่สุดในโลกด้วยความสูง 153 เมตรตั้งตระหง่านอยู่ใจกลางเมือง'),
  'changzhou/comb': ('งานหัตถกรรมหวี', 'หวีจากฉางโจวที่มีประวัติศาสตร์ยาวนานนับพันปีเคยเป็นของขวัญล้ำค่าในวังหลวง'),
  'changzhou/canal': ('คลองต้ายวิ่นเหอ', 'ริมฝั่งคลองเป็นจุดเดินเล่นยอดนิยมเพื่อชมย่านเมืองเก่าและแสงสีในยามค่ำคืน'),
  'shaoxing/wine': ('เหล้าเส้าซิง', 'เหล้าข้าวสีเหลืองที่มีชื่อเสียงในการปรุงอาหารจีนแห่งนี้มีการหมักบ่มมานานนับพันปี'),
  'shaoxing/bridge': ('สะพานหินโบราณ', 'เมืองเส้าซิงที่เต็มไปด้วยลำคลองยังคงอนุรักษ์สะพานหินโค้งไว้หลายร้อยแห่ง'),
  'shaoxing/pen': ('แหล่งกำเนิดอักษรวิจิตร', 'ศาลาหลานถิงของปรมาจารย์หวังซีจือถือเป็นสถานที่ศักดิ์สิทธิ์ของศิลปะการเขียนพู่กันจีน'),
  'shaoxing/boat': ('เรืออูเผิง', 'เรือหลังคาสีดำที่ใช้เท้าถ่อเป็นพาหนะคลาสสิกในการล่องไปตามลำคลอง'),
  'bengbu/shell': ('ท่าเรือไข่มุก', 'ชื่อเมืองมีความหมายว่าท่าเรือหอย ซึ่งในอดีตเคยมีชื่อเสียงเรื่องไข่มุกจากแม่น้ำหวย'),
  'bengbu/train': ('สถานีรถไฟเปิ่งปู้', 'เมืองนี้เติบโตขึ้นจากการเป็นจุดเชื่อมต่อสำคัญของเส้นทางรถไฟสายเหนือ-ใต้ที่ข้ามแม่น้ำหวย'),
  'bengbu/river': ('แม่น้ำหวย', 'แม่น้ำสายสำคัญที่ถือเป็นเส้นแบ่งเขตทางภูมิศาสตร์ระหว่างจีนตอนเหนือและตอนใต้ไหลผ่านที่นี่'),
  'bengbu/blossom': ('เทศกาลชมดอกไม้', 'สวนสาธารณะริมแม่น้ำจะเต็มไปด้วยสีสันของงานเทศกาลชมดอกไม้ในช่วงฤดูใบไม้ผลิ'),
  'jiujiang/mountain': ('เขาหลูซาน', 'ยอดเขาที่ปกคลุมด้วยหมอกของเขาหลูซานได้รับการขึ้นทะเบียนเป็นมรดกโลกและเป็นแรงบันดาลใจให้แก่กวีและจิตรกรมากมาย'),
  'jiujiang/tea': ('ชาอวิ๋นอู้', 'ชาอวิ๋นอู้ที่ปลูกบนไหล่เขาหลูซานถือเป็นหนึ่งในชาที่มีรสชาติละเมียดละไมที่สุดของจีน'),
  'jiujiang/lake': ('ทะเลสาบโผหยาง', 'ทะเลสาบน้ำจืดที่ใหญ่ที่สุดในจีนแห่งนี้เป็นแหล่งอาศัยของนกกระเรียนนับพันตัวในช่วงฤดูหนาว'),
  'jiujiang/scroll': ('เมืองแห่งบทกวี', 'ประตูเมืองริมแม่น้ำแห่งนี้เป็นสถานที่ที่กวีเอกอย่างไป๋จวีอี้และซูซื่อเคยมาพำนักและรังสรรค์บทกวีไว้'),
  'quanzhou/ship': ('เส้นทางสายไหมทางทะเล', 'เมืองท่าที่ยิ่งใหญ่ที่สุดในยุคกลางแห่งนี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกและเป็นที่รู้จักในชื่อ \'จื่อถง\' ตามบันทึกของมาร์โก โปโล'),
  'quanzhou/mosque': ('มัสยิดชิงจิ้ง', 'มัสยิดหินที่สร้างขึ้นในปี ค.ศ. 1009 แห่งนี้เป็นหนึ่งในมัสยิดที่เก่าแก่ที่สุดในประเทศจีน'),
  'quanzhou/puppet': ('หุ่นเชิดฉวนโจว', 'ศิลปะการแสดงหุ่นเชิดสายของฉวนโจวเป็นมรดกทางวัฒนธรรมบนเวทีที่มีประวัติศาสตร์ยาวนานนับพันปี'),
  'quanzhou/tea': ('ชาทิกวนอิม', 'ชาอูหลงจากเมืองอันซีที่อยู่ใกล้เคียงคือชา \'พระโพธิสัตว์เหล็ก\' ที่มีชื่อเสียงโด่งดังไปทั่วโลก'),
  'shanghai/pearl': ('หอไข่มุกตะวันออก', 'หอคอยที่มีรูปทรงลูกบอลสีชมพูโดดเด่นริมแม่น้ำหวงผู่แห่งนี้เป็นสัญลักษณ์ของความทันสมัยในเซี่ยงไฮ้'),
  'shanghai/bund': ('เดอะบันด์', 'ย่านริมน้ำที่มีสถาปัตยกรรมอาคารและโรงแรมเก่าแก่สะท้อนให้เห็นถึงความรุ่งเรืองของเซี่ยงไฮ้ในอดีต'),
  'shanghai/garden': ('สวนอวี้หยวน', 'สวนสไตล์คลาสสิกจากสมัยราชวงศ์หมิงที่เต็มไปด้วยโขดหินและสระน้ำ เปรียบเสมือนโอเอซิสใจกลางเมือง'),
  'shanghai/xlb': ('เสี่ยวหลงเปา', 'แป้งห่อไส้ที่มีน้ำซุปร้อนๆ อยู่ภายในคือเมนูขึ้นชื่อที่เป็นสุดยอดอาหารเช้าของชาวเซี่ยงไฮ้'),
  'hangzhou/lake': ('ทะเลสาบซีหู', 'ทะเลสาบแห่งนี้เต็มไปด้วยทิวทัศน์ของต้นหลิว เกาะน้อยใหญ่ และสะพานโค้ง ซึ่งได้รับการยกย่องในบทกวีจีนมากที่สุด'),
  'hangzhou/tea': ('ชาหลงจิ่ง', 'ชาเขียวหลงจิ่งที่ปลูกบนเนินเขาโดยรอบทะเลสาบถือเป็นชาที่มีชื่อเสียงที่สุดของประเทศจีน'),
  'hangzhou/temple': ('วัดหลิงอิ่น', 'วัดเก่าแก่ที่มีอายุกว่า 1,700 ปีแห่งนี้มีชื่อเสียงโด่งดังจากงานแกะสลักหินและองค์พระพุทธรูปขนาดใหญ่'),
  'hangzhou/silk': ('เมืองผ้าไหม', 'ผ้าไหมหางโจวมีการทอมายาวนานนับพันปีและเป็นแหล่งความมั่งคั่งที่สำคัญของเส้นทางสายไหมในฝั่งตะวันออก'),
  'chongqing/hongya': ('ถ้ำหงหยา', 'กลุ่มอาคารบ้านเรือนบนเสาเข็มที่เกาะอยู่ริมหน้าผาแห่งนี้จะส่องแสงระยิบระยับราวกับเมืองในเทพนิยายยามค่ำคืน'),
  'chongqing/hotpot': ('หม่าล่าหม้อไฟฉงชิ่ง', 'หม้อไฟที่เดือดพล่านไปด้วยน้ำมันรสเผ็ดร้อนและพริกหอมชาคือจิตวิญญาณอันเร่าร้อนของเมืองแห่งขุนเขาแห่งนี้'),
  'chongqing/monorail': ('รถไฟฟ้ารางเดี่ยว', 'ภาพรถไฟฟ้าที่วิ่งทะลุผ่านตัวตึกเป็นสัญลักษณ์อันโดดเด่นของเมืองที่สร้างขึ้นบนภูเขาแห่งนี้'),
  'chongqing/river': ('ช่องเขาแยงซี', 'ท่าเรือแห่งนี้เป็นจุดเริ่มต้นของการล่องเรือชมช่องเขาแยงซี ซึ่งเป็นจุดที่เมืองตั้งตระหง่านอยู่ตรงจุดบรรจบของแม่น้ำสองสาย'),
  'dalian/square': ('จัตุรัสซิงไห่', 'จัตุรัสกลางเมืองที่ใหญ่ที่สุดในเอเชียแห่งนี้เป็นสถานที่จัดงานเทศกาลและการแสดงต่างๆ ริมชายฝั่งทะเล'),
  'dalian/beach': ('ชายหาดต้าเหลียน', 'ด้วยเวิ้งอ่าวหินและอากาศที่เย็นสบายในช่วงฤดูร้อน ทำให้ต้าเหลียนเป็นเมืองตากอากาศริมทะเลที่ได้รับความนิยมที่สุดในภาคเหนือ'),
  'dalian/football': ('เมืองแห่งฟุตบอล', 'ที่นี่เปรียบเสมือนอู่ข้าวอู่น้ำของวงการฟุตบอลจีน เนื่องจากเป็นถิ่นกำเนิดของสโมสรที่ประสบความสำเร็จมากที่สุดในประเทศ'),
  'dalian/seafood': ('อาหารทะเล', 'หอยเชลล์ กุ้ง และหอยเม่นจากทะเลเหลืองที่เย็นจัดเป็นวัตถุดิบชั้นเลิศที่ประดับอยู่บนโต๊ะอาหารของเมืองนี้'),
  'shenyang/palace': ('พระราชวังมุกเดน', 'พระราชวังแห่งแรกของราชวงศ์ชิง ซึ่งเปรียบเสมือนน้องชายขนาดกะทัดรัดของพระราชวังต้องห้ามในปักกิ่ง'),
  'shenyang/tomb': ('สุสานราชวงศ์ชิง', 'สุสานทิศตะวันออกและทิศเหนือที่ล้อมรอบเมืองเป็นที่ตั้งของสุสานอันยิ่งใหญ่ของเหล่าผู้ก่อตั้งราชวงศ์'),
  'shenyang/factory': ('แหล่งกำเนิดอุตสาหกรรม', 'อุตสาหกรรมหนักของจีนถือกำเนิดขึ้นที่นี่ โดยมีโรงงานขนาดใหญ่มากมายจนได้รับฉายาว่าเป็นรูห์รแห่งตะวันออก'),
  'shenyang/dumpling': ('เกี๊ยวเหล่าเปียน', 'เกี๊ยวนึ่งสูตรเหล่าเปียนที่มีประวัติยาวนานกว่าสองร้อยปีถือเป็นเมนูขึ้นชื่อของชาวจีนภาคเหนือ'),
  'hefei/judge': ('ศาลท่านเปา', 'เปาบุ้นจิ้นผู้เป็นสัญลักษณ์แห่งความยุติธรรมถือกำเนิดที่นี่ ศาลแห่งนี้จึงเปรียบเสมือนอนุสรณ์สถานแห่งความซื่อสัตย์'),
  'hefei/science': ('เมืองแห่งวิทยาศาสตร์', 'ศูนย์กลางด้านเทคโนโลยีที่รวบรวมมหาวิทยาลัยและห้องปฏิบัติการชั้นนำของจีนเอาไว้มากมาย'),
  'hefei/lake': ('ทะเลสาบเฉาหู', 'หนึ่งในห้าทะเลสาบน้ำจืดที่ใหญ่ที่สุดของจีน ซึ่งมีชื่อเสียงในเรื่องปลาขาวและปูรสเลิศ'),
  'hefei/cake': ('ขนมเปี๊ยะงาหลูโจว', 'ขนมเปี๊ยะงาไส้หวานเป็นขนมโบราณที่สืบทอดกันมาอย่างยาวนานของเมืองหลูโจว'),
  'foshan/wingchun': ('มวยหย่งชุน', 'เมืองแห่งต้นกำเนิดมวยหย่งชุน ซึ่งเป็นรากเหง้าวิชาการต่อสู้ของยิปมันและบรูซ ลี'),
  'foshan/lion': ('เชิดสิงโต', 'เมืองหลวงแห่งการเชิดสิงโตภาคใต้ที่เต็มไปด้วยสีสันตระการตาจากการแสดงกระโดดเสาดอกเหมย'),
  'foshan/ceramic': ('เครื่องปั้นดินเผาฉือวาน', 'เตาเผาโบราณอายุนับพันปียังคงผลิตตุ๊กตาดินเผาฉือวานที่มีเอกลักษณ์และดูมีชีวิตชีวา'),
  'foshan/opera': ('งิ้วกวางตุ้ง', 'ศิลปะการแสดงบนเวทีที่เป็นที่รักที่สุดของชาวจีนภาคใต้ได้เติบโตและรุ่งเรืองขึ้นบนแผ่นดินแห่งนี้'),
  'guiyang/pavilion': ('ศาลาเจี่ยซิ่ว', 'ศาลาสามชั้นริมแม่น้ำหนานหมิงแห่งนี้เป็นสัญลักษณ์คู่บ้านคู่เมืองกุ้ยหยางมานานกว่า 400 ปี'),
  'guiyang/sourfish': ('ต้มปลาซุปเปรี้ยว', 'เมนูขึ้นชื่อของกุ้ยโจวคือปลาที่ต้มในน้ำซุปมะเขือเทศหมักรสเปรี้ยวกลมกล่อม'),
  'guiyang/waterfall': ('น้ำตกหวงกั่วซู่', 'หนึ่งในน้ำตกที่ใหญ่ที่สุดในเอเชียที่ไหลลงมาอย่างทรงพลังจนเกิดเป็นสายรุ้งงดงาม'),
  'guiyang/miao': ('วัฒนธรรมชาวม้ง', 'เทศกาลและงานปักผ้าของชาวม้งผู้สวมเครื่องประดับเงินอันวิจิตรช่วยสร้างสีสันให้กับหมู่บ้านบนภูเขา'),
  'changchun/film': ('เมืองแห่งภาพยนตร์', 'ที่นี่คือแหล่งกำเนิดภาพยนตร์จีนและได้รับฉายาว่าเป็นฮอลลีวูดแห่งโลกตะวันออก'),
  'changchun/car': ('เมืองแห่งยานยนต์', 'เมืองหลวงแห่งอุตสาหกรรมรถยนต์ของจีนซึ่งเป็นจุดเริ่มต้นของการผลิตรถยนต์ที่สร้างขึ้นด้วยฝีมือคนจีนเป็นครั้งแรก'),
  'changchun/palace': ('พระราชวังหุ่นเชิด', 'พระราชวังแห่งนี้เป็นที่ประทับของจักรพรรดิองค์สุดท้ายและเป็นประจักษ์พยานเงียบงันต่อประวัติศาสตร์อันผันผวน'),
  'changchun/snow': ('หิมะฤดูหนาว', 'ในช่วงฤดูหนาวอันยาวนาน เมืองทั้งเมืองจะส่องประกายไปด้วยประติมากรรมน้ำแข็งและลานสกี'),
  'xining/lake': ('ทะเลสาบชิงไห่', 'ทะเลสาบน้ำเค็มที่ใหญ่ที่สุดในจีนแห่งนี้มีชื่อเสียงจากทุ่งดอกเรปซีดสีเหลืองอร่ามที่ล้อมรอบในช่วงฤดูร้อน'),
  'xining/monastery': ('วัดถ่าเอ๋อร์', 'หนึ่งในหกวัดที่ยิ่งใหญ่ที่สุดของพุทธศาสนาแบบทิเบต ซึ่งมีชื่อเสียงโด่งดังจากการแกะสลักเนยจามรี'),
  'xining/flower': ('ดอกเรปซีด', 'ในเดือนกรกฎาคม ที่ราบสูงแห่งนี้จะถูกปกคลุมไปด้วยทุ่งดอกเรปซีดสีทองสุดลูกหูลูกตา'),
  'xining/lamb': ('เนื้อจามรีและเนื้อแกะ', 'บะหมี่ดึงมือและเนื้อแกะย่างสไตล์ชาวหุยและชาวทิเบตคือรสชาติที่เป็นเอกลักษณ์ของที่ราบสูงแห่งนี้'),
  'guilin/karst': ('เขาหินปูนแม่น้ำหลี', 'ยอดเขาหินปูนที่โผล่พ้นสายหมอกคือทิวทัศน์ที่ปรากฏอยู่บนธนบัตรใบละ 20 หยวน'),
  'guilin/elephant': ('เขาช้างงวง', 'โขดหินรูปทรงคล้ายช้างที่กำลังหย่อนงวงลงในแม่น้ำคือสัญลักษณ์อันเป็นที่รักของเมืองนี้'),
  'guilin/terrace': ('นาขั้นบันไดหลงจี๋', 'นาขั้นบันไดสันหลังมังกรที่โอบล้อมไหล่เขาเปรียบเสมือนบันไดแห่งความเพียรพยายามที่สั่งสมมานานหลายศตวรรษ'),
  'guilin/osmanthus': ('ดอกหอมหมื่นลี้', 'ชื่อเมืองกุ้ยหลินแปลว่าป่าหอมหมื่นลี้ ในช่วงฤดูใบไม้ร่วงทั่วทั้งเมืองจะอบอวลไปด้วยกลิ่นหอมหวานของดอกไม้ชนิดนี้'),
  'wenzhou/merchant': ('จิตวิญญาณนักธุรกิจ', 'ผู้ประกอบการชาวเวินโจวได้รับฉายาว่าเป็นชาวยิวแห่งเมืองจีน โดยพวกเขาสร้างเครือข่ายธุรกิจไปทั่วโลก'),
  'wenzhou/shoe': ('รองเท้าและเครื่องหนัง', 'รองเท้าหนังจำนวนมหาศาลที่ใช้กันทั่วโลกล้วนผลิตมาจากเมืองแห่งโรงงานอุตสาหกรรมแห่งนี้'),
  'wenzhou/mountain': ('เขาเยี่ยนตั่ง', 'ภูเขาแห่งนี้มีชื่อเสียงจากน้ำตกและยอดเขาที่แหลมคม จนได้รับการยกย่องว่าเป็นภูเขาแห่งแรกริมทะเล'),
  'wenzhou/seafood': ('อาหารทะเล', 'ปลาหมึก หอยเชลล์ และปลาจากทะเลจีนตะวันออกคือวัตถุดิบหลักบนโต๊ะอาหารของชาวเมืองนี้'),
  'tangshan/memorial': ('อนุสรณ์สถานแผ่นดินไหว', 'สวนอนุสรณ์สถานเหตุการณ์แผ่นดินไหวครั้งใหญ่ในปี 1976 คือสัญลักษณ์ของการเกิดใหม่ของเมืองนี้'),
  'tangshan/coal': ('เหมืองถ่านหินและทางรถไฟแห่งแรก', 'ที่นี่คือจุดกำเนิดอุตสาหกรรมสมัยใหม่ของจีน โดยเป็นที่ตั้งของเหมืองถ่านหินและทางรถไฟแห่งแรกของประเทศ'),
  'tangshan/ceramic': ('เครื่องปั้นดินเผาถังซาน', 'เมืองแห่งเครื่องเคลือบดินเผาทางตอนเหนือที่มีชื่อเสียงโดดเด่นเรื่องโบนไชน่าอันประณีตงดงาม'),
  'tangshan/lake': ('สวนสาธารณะหนานหู', 'สวนสาธารณะริมทะเลสาบที่ปรับปรุงจากพื้นที่เหมืองเก่าจนกลายเป็นปอดสีเขียวของเมือง'),
  'anshan/steel': ('เมืองเหล็กกล้า', 'เมืองที่เป็นฐานการผลิตเหล็กกล้าที่ใหญ่ที่สุดของจีนจนได้รับฉายาว่าเป็นเมืองหลวงแห่งเหล็กกล้าของประเทศ'),
  'anshan/jade': ('หยกซิ่วเหยียน', 'เมืองแห่งหยกของจีนที่เป็นที่ตั้งของงานแกะสลักหยกที่มีขนาดใหญ่ที่สุดในโลก'),
  'anshan/mountain': ('เขาเชียนซาน', 'ยอดเขาศักดิ์สิทธิ์ทางตอนเหนือที่เต็มไปด้วยวัดวาอารามและทัศนียภาพของยอดเขาที่สวยงามดั่งดอกบัวพันกลีบ'),
  'anshan/spring': ('น้ำพุร้อนถังกังจื่อ', 'แหล่งน้ำพุร้อนเพื่อการบำบัดที่มีประวัติยาวนานนับพันปีและเคยเป็นสถานที่พักผ่อนของเหล่าจักรพรรดิในอดีต'),
  'linyi/market': ('ตลาดค้าส่งหลินอี๋', 'ศูนย์กลางการค้าส่งที่ใหญ่ที่สุดในภาคเหนือของจีนซึ่งเป็นจุดกระจายสินค้าไปทั่วประเทศ'),
  'linyi/brush': ('บ้านเกิดปรมาจารย์พู่กัน', 'เมืองแห่งศิลปะการเขียนพู่กันที่เป็นบ้านเกิดของหวังซีจือ ปรมาจารย์ด้านอักษรศิลป์ผู้ยิ่งใหญ่ของจีน'),
  'linyi/mountain': ('เขาเหมิงซาน', 'ภูเขาที่สูงเป็นอันดับสองของมณฑลซานตง ซึ่งเปรียบเสมือนแหล่งผลิตอากาศบริสุทธิ์ที่เต็มไปด้วยน้ำตกสวยงาม'),
  'linyi/pancake': ('แผ่นแป้งอี้เหมิง', 'แผ่นแป้งข้าวโพดบางกรอบที่เป็นอาหารหลักดั้งเดิมของชาวเขาในเขตอี้เหมิงมาอย่างยาวนาน'),
  'cangzhou/lion': ('สิงโตเหล็กชางโจว', 'รูปปั้นสิงโตเหล็กหล่อขนาดมหึมาที่มีอายุเก่าแก่กว่า 1,100 ปี ซึ่งเป็นสัญลักษณ์อันภาคภูมิใจของเมือง'),
  'cangzhou/martial': ('ศิลปะการต่อสู้ชางโจว', 'เมืองแห่งวิทยายุทธที่เป็นแหล่งกำเนิดของปรมาจารย์และสำนักศิลปะการต่อสู้ที่มีชื่อเสียงมากมาย'),
  'cangzhou/canal': ('คลองขุดต้ายวิ่นเหอ', 'คลองขุดปักกิ่ง-หางโจวที่ไหลผ่านตัวเมือง โดยยังคงหลงเหลือร่องรอยของท่าเรือเก่าแก่ให้เห็นจนถึงปัจจุบัน'),
  'cangzhou/jujube': ('พุทราทองคำ', 'พุทราพันธุ์เปลือกบางรสหวานฉ่ำที่ได้รับการยกย่องว่าเป็นราชาแห่งผลไม้อบแห้ง'),
  'nantong/textile': ('เมืองแห่งสิ่งทอ', 'เมืองนี้เป็นศูนย์กลางอุตสาหกรรมสิ่งทอของจีนที่ส่งออกผ้าฝ้ายไปจำหน่ายทั่วโลก'),
  'nantong/mountain': ('เขาหลางซาน', 'ภูเขาศักดิ์สิทธิ์ห้ายอดที่ตั้งอยู่บริเวณปากแม่น้ำแยงซี เป็นจุดหมายปลายทางยอดนิยมสำหรับการแสวงบุญและชมทิวทัศน์'),
  'nantong/kite': ('ว่าวเสียงหวีด', 'ว่าวปันเหยาที่ติดตั้งอุปกรณ์ส่งเสียงหวีดหวิวเป็นงานฝีมือดั้งเดิมอันเป็นเอกลักษณ์ของเมืองนี้'),
  'nantong/school': ('ต้นกำเนิดการศึกษาแผนใหม่', 'จางเจียน นักอุตสาหกรรมผู้มีชื่อเสียงได้ก่อตั้งโรงเรียนและพิพิธภัณฑ์สมัยใหม่แห่งแรกของจีนขึ้นที่นี่'),
  'taizhou/opera': ('เหมยหลานฟาง', 'เมืองนี้เป็นบ้านเกิดของเหมยหลานฟาง ปรมาจารย์ผู้เป็นตำนานแห่งงิ้วปักกิ่ง'),
  'taizhou/tea': ('น้ำชาตอนเช้า', 'วัฒนธรรมการรับประทานติ่มซำและจิบน้ำชาในยามเช้าถือเป็นกิจวัตรประจำวันอันเป็นเอกลักษณ์ของชาวเมือง'),
  'taizhou/boat': ('เทศกาลเรือฉินถง', 'ในช่วงฤดูใบไม้ผลิจะมีเทศกาลแข่งเรือที่เต็มไปด้วยฝีพายหลายร้อยคน ทำให้แม่น้ำกลับมามีชีวิตชีวาอีกครั้ง'),
  'taizhou/meatball': ('หมูสับหัวสิงโต', 'เมนูหมูสับก้อนโตเนื้อนุ่มที่เรียกว่าหัวสิงโตเป็นอาหารจานคลาสสิกของอาหารสไตล์หวยหยาง'),
  'jinhua/ham': ('แฮมจินหัว', 'แฮมสีแดงที่ผ่านกรรมวิธีการบ่มแบบดั้งเดิมมานานหลายศตวรรษนี้ถือเป็นแฮมที่มีชื่อเสียงที่สุดในจีน'),
  'jinhua/film': ('กองถ่ายเหิงเตี้ยน', 'สตูดิโอถ่ายทำภาพยนตร์กลางแจ้งที่ใหญ่ที่สุดในโลก ซึ่งเป็นสถานที่ถ่ายทำละครย้อนยุคจำนวนนับไม่ถ้วน'),
  'jinhua/cave': ('ถ้ำซวงหลง', 'ถ้ำใต้ดินที่ต้องนั่งเรือลอดผ่านช่องหินเตี้ยๆ เข้าไป ซึ่งสร้างความตื่นตาตื่นใจให้กับผู้มาเยือนเป็นอย่างมาก'),
  'jinhua/bridge': ('สะพานโบราณ', 'สะพานหินโค้งและเมืองริมน้ำที่สะท้อนถึงความงดงามตามแบบฉบับของภูมิภาคเจียงหนาน'),
  'wuhu/park': ('สวนสนุกฟางเท่อ', 'หนึ่งในสวนสนุกที่ใหญ่ที่สุดของจีนที่มอบความสนุกสนานตื่นเต้นให้กับครอบครัวได้ตลอดทั้งวัน'),
  'wuhu/ironart': ('ภาพวาดเหล็ก', 'งานศิลปะภาพวาดเหล็กที่ประดิษฐ์ขึ้นจากเหล็กดัดอย่างประณีตเป็นงานฝีมือที่มีประวัติยาวนานกว่า 300 ปี'),
  'wuhu/rice': ('ท่าเรือข้าว', 'เมืองริมแม่น้ำแยงซีแห่งนี้เคยเป็นตลาดค้าข้าวที่ใหญ่ที่สุดของจีนในอดีต'),
  'wuhu/river': ('ท่าเรือแม่น้ำแยงซี', 'ท่าเรือที่คึกคักแห่งนี้เปรียบเสมือนประตูสู่ทะเลของมณฑลอันฮุย'),
  'huangshan/peak': ('ภูเขาหวงซาน', 'ภูเขาที่มีชื่อเสียงที่สุดในจีน โดดเด่นด้วยยอดเขาหินแกรนิต ทะเลหมอก และต้นสนรูปร่างแปลกตา'),
  'huangshan/village': ('หมู่บ้านหงชุน', 'หมู่บ้านสไตล์ฮุยที่มีกำแพงสีขาวและลำธารไหลผ่าน ได้รับการขึ้นทะเบียนเป็นมรดกโลกและมีความงดงามราวกับภาพวาด'),
  'huangshan/tea': ('ชาเหมาเฟิง', 'ชาเขียวชั้นเลิศที่เก็บเกี่ยวจากบนยอดเขาที่มีหมอกปกคลุม และเป็นหนึ่งในสิบสุดยอดชาที่มีชื่อเสียงที่สุดของจีน'),
  'huangshan/ink': ('หมึกและศิลปะหุยโจว', 'หมึกจีน งานแกะสลักไม้ และศิลปะการเขียนพู่กันถือเป็นสมบัติทางวัฒนธรรมอันล้ำค่าของภูมิภาคนี้'),
  'yichun/moon': ('ภูเขาหมิงเยว่', 'ภูเขาแห่งพระจันทร์สว่างที่มีชื่อเสียงในเรื่องบ่อน้ำพุร้อนและทิวทัศน์สวยงามจากการนั่งกระเช้าไฟฟ้า'),
  'yichun/spring': ('บ่อน้ำพุร้อน', 'น้ำพุร้อนที่อุดมไปด้วยแร่ธาตุซีลีเนียมหายาก ทำให้เมืองนี้กลายเป็นศูนย์กลางการแช่น้ำพุร้อนของจีน'),
  'yichun/zen': ('พุทธศาสนานิกายฉาน', 'วัดบนภูเขาที่เป็นรากฐานของนิกายฉานในจีน เชิญชวนให้ผู้มาเยือนได้สัมผัสกับความสงบทางจิตใจ'),
  'yichun/rice': ('ที่ราบลุ่มแม่น้ำหยวนเหอ', 'ที่ราบอันอุดมสมบูรณ์แห่งนี้เป็นแหล่งเพาะปลูกข้าวที่สำคัญของมณฑลเจียงซีมาอย่างยาวนาน'),
  'zhangzhou/narcissus': ('ดอกนาร์ซิสซัส', 'แหล่งปลูกดอกนาร์ซิสซัสที่มีชื่อเสียงที่สุดของจีน ซึ่งถือเป็นสัญลักษณ์แห่งเทศกาลฤดูใบไม้ผลิ'),
  'zhangzhou/tulou': ('บ้านดินถู่โหลว', 'ป้อมปราการดินทรงกลมขนาดใหญ่ที่ได้รับการขึ้นทะเบียนเป็นมรดกโลก โดยเป็นที่อยู่อาศัยของคนทั้งหมู่บ้านภายใต้หลังคาเดียวกัน'),
  'zhangzhou/banana': ('ผลไม้เมืองร้อน', 'สวนกล้วย ลำไย และส้มเขียวหวาน ทำให้พื้นที่สามเหลี่ยมปากแม่น้ำแห่งนี้เขียวชอุ่มตลอดทั้งปี'),
  'zhangzhou/coast': ('เกาะตงซาน', 'เกาะที่เป็นดั่งไข่มุกแห่งชายฝั่งทางใต้ โดดเด่นด้วยหาดทรายสีทองและหมู่บ้านชาวประมง'),
  'guangzhou/tower': ('แคนตัน ทาวเวอร์', 'หอคอยที่สูงที่สุดแห่งหนึ่งของโลกซึ่งมีรูปทรงเพรียวบางและประดับประดาด้วยแสงสีสวยงามยามค่ำคืน'),
  'guangzhou/dimsum': ('ติ่มซำ', 'วัฒนธรรมการดื่มชาและทานติ่มซำในเข่งไม้ไผ่ถือเป็นหัวใจสำคัญของการรับประทานอาหารแบบกวางตุ้ง'),
  'guangzhou/academy': ('ศาลบรรพชนตระกูลเฉิน', 'ศาลบรรพชนแห่งนี้เป็นผลงานชิ้นเอกของงานฝีมือชาวกวางตุ้ง โดดเด่นด้วยงานแกะสลักไม้และเครื่องปั้นดินเผาที่วิจิตรบรรจง'),
  'guangzhou/flower': ('นครแห่งดอกไม้', 'กวางโจวได้รับฉายาว่านครแห่งดอกไม้ เพราะมีดอกไม้บานสะพรั่งตลอดทั้งปีและมีการจัดงานเทศกาลดอกไม้อย่างยิ่งใหญ่ในช่วงเทศกาลตรุษจีน'),
  'wuhan/crane': ('หอเหลือง', 'หอคอยเก่าแก่พันปีที่ตั้งตระหง่านอยู่ริมแม่น้ำแยงซีแห่งนี้ เป็นแรงบันดาลใจให้กับบทกวีจีนที่มีชื่อเสียงมากมาย'),
  'wuhan/noodle': ('บะหมี่แห้งร้อน', 'บะหมี่แห้งคลุกซอสงาเป็นเมนูอาหารเช้าที่ขาดไม่ได้ของชาวอู่ฮั่น'),
  'wuhan/duckneck': ('คอเป็ดพะโล้รสเผ็ด', 'คอเป็ดพะโล้รสจัดจ้านเป็นของว่างยอดนิยมที่ชาวเมืองมักซื้อมาทานคู่กับการพูดคุยยามค่ำคืน'),
  'wuhan/university': ('ซากุระมหาวิทยาลัยอู่ฮั่น', 'ในช่วงฤดูใบไม้ผลิ ดอกซากุระที่บานสะพรั่งภายในมหาวิทยาลัยอู่ฮั่นจะดึงดูดนักท่องเที่ยวหลายพันคนให้มาเยี่ยมชม'),
  'tianjin/eye': ('เทียนจินอาย', 'ชิงช้าสวรรค์ที่สร้างอยู่บนสะพานแห่งนี้ช่วยให้มองเห็นทัศนียภาพของแม่น้ำทั้งสองฝั่งได้อย่างชัดเจน'),
  'tianjin/baozi': ('ซาลาเปาโกวปู้หลี่', 'ซาลาเปาไส้หมูจีบสวยที่เป็นเมนูขึ้นชื่อประจำเมืองมานานกว่า 150 ปี'),
  'tianjin/crosstalk': ('เซี่ยงเซิง', 'ศิลปะการแสดงตลกพูดคุยสองคนที่เป็นวัฒนธรรมดั้งเดิมของเทียนจิน ซึ่งมีต้นกำเนิดมาจากโรงน้ำชา'),
  'tianjin/architecture': ('ย่านสถาปัตยกรรมยุโรป', 'กลุ่มวิลล่าสไตล์ยุโรปในย่านถนนสายหลักทั้งห้าทำให้เทียนจินได้รับฉายาว่าเป็นพิพิธภัณฑ์สถาปัตยกรรมกลางแจ้ง'),
  'xiamen/island': ('เกาะกูลั่งอวี่', 'เกาะที่ได้รับการขึ้นทะเบียนเป็นมรดกโลกแห่งนี้เป็นพิพิธภัณฑ์กลางแจ้งที่เต็มไปด้วยวิลล่าสไตล์โคโลเนียลและทางเดินที่ปราศจากรถยนต์'),
  'xiamen/piano': ('เกาะเปียโน', 'เกาะกูลั่งอวี่ได้รับฉายาว่าเกาะเปียโน เนื่องจากเป็นสถานที่ที่มีจำนวนเปียโนต่อประชากรสูงที่สุดแห่งหนึ่ง'),
  'xiamen/egret': ('นกยางขาว', 'นกยางขาวเป็นสัญลักษณ์ประจำเมืองที่ทำให้นึกถึงชื่อเดิมของเมืองนี้ที่เรียกว่าเกาะนกยาง'),
  'xiamen/oyster': ('หอยทอด', 'หอยนางรมสดทอดกับไข่จนกรอบนอกนุ่มในเป็นเมนูเด็ดที่เป็นหัวใจของอาหารทะเลในเมืองนี้'),
  'harbin/ice': ('เทศกาลน้ำแข็ง', 'เทศกาลฤดูหนาวที่จัดแสดงปราสาทน้ำแข็งยักษ์ประดับไฟที่ใหญ่ที่สุดในโลก'),
  'harbin/cathedral': ('มหาวิหารเซนต์โซเฟีย', 'มหาวิหารนิกายออร์ทอดอกซ์ที่มีโดมรูปหัวหอมแห่งนี้เป็นสัญลักษณ์ที่สะท้อนถึงอดีตอันรุ่งเรืองในแบบยุโรปของเมืองฮาร์บิน'),
  'harbin/sausage': ('ไส้กรอกแดง', 'ไส้กรอกรมควันสไตล์รัสเซียสีแดงสดเป็นอาหารขึ้นชื่อที่มีประวัติศาสตร์ยาวนานกว่าร้อยปีของเมืองนี้'),
  'harbin/accordion': ('เมืองแห่งดนตรี', 'ด้วยมรดกทางวัฒนธรรมจากรัสเซีย ฮาร์บินจึงเป็นเมืองที่ก่อตั้งวงดนตรีซิมโฟนีออร์เคสตราวงแรกของจีน'),
  'fuzhou/alley': ('ซานฟางชีเซี่ยง', 'ย่านเมืองเก่าที่มีกำแพงสีขาวและหลังคาสีดำแห่งนี้เปรียบเสมือนพิพิธภัณฑ์ที่มีชีวิตซึ่งจัดแสดงสถาปัตยกรรมในยุคราชวงศ์หมิงและชิง'),
  'fuzhou/banyan': ('เมืองแห่งต้นไทร', 'ต้นไทรยักษ์โบราณที่แผ่กิ่งก้านให้ร่มเงาไปทั่วถนนทำให้ฝูโจวได้รับฉายาว่าเป็นเมืองแห่งต้นไทร'),
  'fuzhou/hotspring': ('บ่อน้ำพุร้อน', 'น้ำพุร้อนธรรมชาติที่ผุดขึ้นมาใจกลางเมืองถูกนำมาใช้ในโรงอาบน้ำสาธารณะมานานนับพันปี'),
  'fuzhou/soup': ('พระกระโดดกำแพง', 'ซุปเลิศรสที่เคี่ยวจากวัตถุดิบชั้นเลิศนานาชนิดนี้ถือเป็นสุดยอดเมนูอาหารขึ้นชื่อของมณฑลฝูเจี้ยน'),
  'dongguan/robot': ('โรงงานของโลก', 'ตงกวนเป็นฐานการผลิตอุปกรณ์อิเล็กทรอนิกส์ขนาดใหญ่ของโลกด้วยระบบโรงงานที่ใช้เทคโนโลยีอัตโนมัติ'),
  'dongguan/basketball': ('เมืองแห่งบาสเกตบอล', 'ตงกวนเป็นที่ตั้งของสโมสรบาสเกตบอลที่ประสบความสำเร็จมากที่สุดในประเทศจีน'),
  'dongguan/keyuan': ('สวนเข่อหยวน', 'หนึ่งในสี่สวนคลาสสิกที่มีชื่อเสียงที่สุดของมณฑลกวางตุ้ง ซึ่งโดดเด่นด้วยสระน้ำและศาลาที่สวยงาม'),
  'dongguan/cannon': ('ป้อมปราการหู่เหมิน', 'ป้อมปราการหู่เหมินเป็นสถานที่ทางประวัติศาสตร์ที่เกิดเหตุการณ์ทำลายฝิ่นและเป็นจุดเริ่มต้นของสงครามฝิ่น'),
  'lanzhou/beefnoodle': ('บะหมี่เนื้อหลานโจว', 'ด้วยน้ำซุปเนื้อใสและเส้นบะหมี่ที่นวดด้วยมือ ทำให้หลานโจวได้รับการยกย่องว่าเป็นเมืองหลวงแห่งบะหมี่ของจีน'),
  'lanzhou/waterwheel': ('กังหันน้ำ', 'กังหันน้ำขนาดใหญ่ริมแม่น้ำเหลืองเป็นสัญลักษณ์ที่แสดงถึงภูมิปัญญาด้านวิศวกรรมชลประทานที่มีมานานหลายศตวรรษ'),
  'lanzhou/statue': ('อนุสาวรีย์มารดาแม่น้ำเหลือง', 'รูปปั้นแม่และลูกที่ตั้งอยู่ริมฝั่งแม่น้ำเป็นตัวแทนของสายน้ำที่หล่อเลี้ยงอารยธรรมจีนมาอย่างยาวนาน'),
  'lanzhou/raft': ('แพหนังแกะ', 'แพแบบดั้งเดิมที่ทำจากหนังแกะพองลมยังคงถูกนำมาใช้ล่องไปตามแม่น้ำเหลืองจนถึงปัจจุบัน'),
  'urumqi/bazaar': ('ตลาดแกรนด์บาซาร์', 'ตลาดแห่งนี้เต็มไปด้วยหอคอยสูงและร้านขายเครื่องเทศที่สะท้อนสีสันแห่งเส้นทางสายไหม'),
  'urumqi/tianshan': ('ทะเลสาบเทียนฉือ', 'ทะเลสาบเทียนฉือตั้งอยู่ใต้เทือกเขาหิมะเทียนซานและรายล้อมไปด้วยป่าสนอันเขียวขจี'),
  'urumqi/kebab': ('เนื้อแกะย่าง', 'เนื้อแกะเสียบไม้ย่างบนเตาถ่านที่ปรุงรสด้วยเครื่องเทศเป็นเมนูสำคัญบนโต๊ะอาหารของชาวอุยกูร์'),
  'urumqi/dance': ('ระบำอุยกูร์', 'การร่ายรำหมุนตัวของชาวอุยกูร์ที่มาพร้อมกับเสียงกลองและเครื่องดนตรีราวัปช่วยสร้างสีสันให้กับทุกงานเฉลิมฉลอง'),
  'haikou/coconut': ('เมืองแห่งมะพร้าว', 'ถนนที่เรียงรายไปด้วยต้นมะพร้าวทำให้ไหโข่วได้รับฉายาว่าเป็นเมืองแห่งมะพร้าว'),
  'haikou/arcade': ('ย่านตึกแถวฉีโหลว', 'อาคารสถาปัตยกรรมแบบฉีโหลวที่มีทางเดินใต้ถุนตึกช่วยสร้างบรรยากาศถนนที่มีร่มเงาในเขตภาคใต้'),
  'haikou/crater': ('อุทยานภูเขาไฟ', 'ปากปล่องภูเขาไฟที่ดับแล้วกลายเป็นอุทยานธรณีวิทยาอันเขียวขจีที่ตั้งอยู่บริเวณชานเมือง'),
  'haikou/turtle': ('ทะเลเขตร้อน', 'น้ำทะเลที่ใสสะอาดและแนวปะการังทำให้ชายฝั่งแห่งนี้เป็นบ้านของเต่าทะเล'),
  'luoyang/grotto': ('ถ้ำหินหลงเหมิน', 'พระพุทธรูปนับหมื่นองค์ที่ถูกแกะสลักลงบนหน้าผาถือเป็นสมบัติทางศิลปะที่ได้รับการขึ้นทะเบียนเป็นมรดกโลก'),
  'luoyang/peony': ('เมืองหลวงแห่งดอกโบตั๋น', 'ดอกโบตั๋นนับพันต้นที่บานสะพรั่งในเดือนเมษายนทำให้ลั่วหยางได้ชื่อว่าเป็นเมืองหลวงแห่งดอกโบตั๋น'),
  'luoyang/whitehorse': ('วัดม้าขาว', 'วัดแห่งนี้ก่อตั้งขึ้นเมื่อปี ค.ศ. 68 และได้รับการยกย่องว่าเป็นวัดพุทธแห่งแรกของจีน'),
  'luoyang/capital': ('เมืองหลวงเก่า', 'ลั่วหยางเคยเป็นเมืองหลวงของ 13 ราชวงศ์และถือเป็นแหล่งกำเนิดสำคัญของอารยธรรมจีน'),
  'shantou/gongfutea': ('ชาฉงฟู', 'การชงชาฉงฟูสไตล์แต้จิ๋วในถ้วยใบเล็กอย่างพิถีพิถันถือเป็นศิลปะแห่งการต้อนรับแขก'),
  'shantou/beefpot': ('หม้อไฟเนื้อ', 'หม้อไฟสไตล์แต้จิ๋วที่ขึ้นชื่อเรื่องการนำเนื้อวัวสดสไลด์บางมาลวกในน้ำซุปเพียงไม่กี่วินาที'),
  'shantou/opera': ('งิ้วแต้จิ๋ว', 'งิ้วแต้จิ๋วที่มีประวัติยาวนานกว่า 600 ปีโดดเด่นด้วยท่วงทำนองที่อ่อนช้อยและเครื่องแต่งกายที่ปักลวดลายอย่างประณีต'),
  'shantou/harbor': ('เมืองท่าซัวเถา', 'ซัวเถาเป็นบ้านเกิดของชาวจีนโพ้นทะเลจำนวนมาก และท่าเรือแห่งนี้ก็เป็นประตูการค้าทางทะเลที่เก่าแก่.'),
  'baoding/mansion': ('จวนผู้ว่าการเป่าติ้ง', 'ที่นี่คือที่ว่าการมณฑลสูงสุดในสมัยราชวงศ์ชิง ซึ่งได้รับการอนุรักษ์ไว้เป็นอย่างดี.'),
  'baoding/donkeyburger': ('ขนมปังเนื้อลา', 'เนื้อลาปรุงรสยัดไส้ในขนมปังแบนกรอบ เป็นอาหารข้างทางขึ้นชื่อของภูมิภาคนี้.'),
  'baoding/balls': ('ลูกเหล็กเป่าติ้ง', 'ลูกเหล็กบริหารมือที่หมุนในฝ่ามือนี้เป็นประเพณีการออกกำลังกายมือที่มีมานานหลายศตวรรษ.'),
  'baoding/reeds': ('บึงไป๋หยางเตี้ยน', 'พื้นที่ชุ่มน้ำที่ใหญ่ที่สุดทางตอนเหนือแห่งนี้เป็นสวรรค์ของนกที่เต็มไปด้วยต้นกกและดอกบัว.'),
  'jilin/rime': ('ปรากฏการณ์น้ำค้างแข็งจี๋หลิน', 'น้ำค้างแข็งสีขาวที่ปกคลุมต้นไม้ริมแม่น้ำซงฮวาเป็นหนึ่งในสี่สิ่งมหัศจรรย์ทางธรรมชาติของจีน.'),
  'jilin/snowboard': ('สกีรีสอร์ตจี๋หลิน', 'ด้วยหิมะที่หนาและฤดูที่ยาวนาน เมืองนี้จึงเป็นหนึ่งในสกีรีสอร์ตชั้นนำทางตอนเหนือ.'),
  'jilin/meteorite': ('พิพิธภัณฑ์อุกกาบาต', 'อุกกาบาตหินที่ใหญ่ที่สุดในโลกซึ่งตกลงมาในปี 1976 จัดแสดงอยู่ที่นี่.'),
  'jilin/skate': ('แม่น้ำซงฮวาแข็งตัว', 'แม่น้ำซงฮวาที่แข็งตัวจะกลายเป็นลานน้ำแข็งที่เต็มไปด้วยนักสเก็ตและผู้คนเดินเล่นในฤดูหนาว.'),
  'ordos/khan': ('สุสานเจงกิสข่าน', 'สุสานอันยิ่งใหญ่ที่สร้างขึ้นเพื่อเป็นเกียรติแก่วีรบุรุษแห่งทุ่งหญ้าเจงกิสข่านแห่งนี้เป็นหัวใจของวัฒนธรรมมองโกล.'),
  'ordos/cashmere': ('ผ้าแคชเมียร์เออร์โดส', 'ผ้าแคชเมียร์ที่ทอจากขนแพะเออร์โดสทำให้เมืองนี้เป็นที่รู้จักในอุตสาหกรรมสิ่งทอระดับโลก.'),
  'ordos/sanddune': ('เนินทรายร้องเพลง', 'เนินทรายขนาดยักษ์ที่ส่งเสียงหึ่งๆ เมื่อคุณเลื่อนลงมา เป็นจุดแวะพักยอดนิยมของทะเลทรายคูบู่ฉี.'),
  'ordos/yurt': ('กระโจมมองโกล', 'กระโจมผ้าสักหลาดสีขาวที่ตั้งอยู่บนทุ่งหญ้าอันกว้างใหญ่เป็นสัญลักษณ์ของชีวิตเร่ร่อน.'),
  'jining/confucius': ('วัดขงจื๊อ', 'ในเมืองชวีฟู่ที่อยู่ใกล้เคียง วัด คฤหาสน์ และสุสานของปราชญ์ขงจื๊อได้รับการขึ้นทะเบียนเป็นมรดกโลกโดยยูเนสโก.'),
  'jining/barge': ('คลองต้ายวิ่นเหอ', 'จี๋หนิงเป็นท่าเรือที่พลุกพล่านบนคลองปักกิ่ง-หางโจว และเป็นศูนย์กลางของวัฒนธรรมคลอง.'),
  'jining/sword': ('วีรบุรุษเหลียงซาน', 'วีรบุรุษผู้กล้า 108 คนจากวรรณกรรมคลาสสิกเรื่อง \'ซ้องกั๋ง\' ได้รวมตัวกัน ณ เนินเขาและบึงแห่งนี้'),
  'jining/fishnet': ('ทะเลสาบเวยซาน', 'ที่ทะเลสาบบัวที่ใหญ่ที่สุดทางตอนเหนือแห่งนี้ ชาวประมงยังคงทอดแหจับปลาด้วยวิถีโบราณ'),
  'langfang/culture': ('ศูนย์วัฒนธรรมเส้นทางสายไหม', 'ศูนย์วัฒนธรรมอันทันสมัยขนาดใหญ่ของเมืองแห่งนี้รวบรวมศิลปะจากเส้นทางสายไหมไว้ในที่เดียว'),
  'langfang/furniture': ('เมืองเฟอร์นิเจอร์', 'อำเภอเซียงเหอที่อยู่ใกล้เคียงเป็นหนึ่งในศูนย์กลางการผลิตและค้าเฟอร์นิเจอร์ที่ใหญ่ที่สุดของจีน'),
  'langfang/tunnel': ('อุโมงค์สงครามโบราณ', 'อุโมงค์ทางทหารใต้ดินอายุนับพันปีเหล่านี้เป็นร่องรอยของการป้องกันชายแดนในอดีต'),
  'langfang/themepark': ('อุทยานเมืองอันดับหนึ่ง', 'สวนสนุกขนาดใหญ่ที่จำลองเมืองโบราณมีกำแพงล้อมรอบแห่งนี้ยินดีต้อนรับทุกครอบครัว'),
  'yancheng/salt': ('เมืองแห่งเกลือ', 'ชื่อของเมืองมีความหมายว่า \'ป้อมเกลือ\' และเป็นเวลานับศตวรรษที่หยานเฉิงเป็นศูนย์กลางการผลิตเกลือของจีน'),
  'yancheng/crane': ('นกกระเรียนมงกุฎแดง', 'พื้นที่ชุ่มน้ำชายฝั่งแห่งนี้เป็นแหล่งอาศัยในฤดูหนาวที่ใหญ่ที่สุดในโลกสำหรับนกกระเรียนมงกุฎแดงป่า'),
  'yancheng/elk': ('กวางมิลู่', 'กวางมิลู่ที่เคยสูญพันธุ์จากธรรมชาติได้กลับมาแพร่พันธุ์อีกครั้งในพื้นที่ชุ่มน้ำแห่งนี้'),
  'yancheng/wetland': ('พื้นที่ชุ่มน้ำชายฝั่ง', 'พื้นที่ราบน้ำขึ้นน้ำลงที่ได้รับการขึ้นทะเบียนโดยยูเนสโกแห่งนี้เป็นจุดแวะพักสำคัญสำหรับนกอพยพทั่วโลก'),
  'huzhou/brush': ('พู่กันหู', 'พู่กันหู ซึ่งเป็นหนึ่งใน \'สี่สมบัติ\' ของการประดิษฐ์อักษรจีน มีการผลิตขึ้นที่นี่'),
  'huzhou/bamboo': ('ทะเลไผ่อานจี๋', 'ป่าไผ่สีเขียวขจีอันกว้างใหญ่ไร้ขอบเขตแห่งนี้ ซึ่งเป็นแรงบันดาลใจให้ภาพยนตร์หลายเรื่อง ช่วยให้บรรยากาศเย็นสบาย'),
  'huzhou/silkworm': ('หนอนไหม', 'ชายฝั่งทางใต้ของทะเลสาบไท่เป็นศูนย์กลางการผลิตผ้าไหมหม่อนมานานนับพันปี'),
  'huzhou/whitetea': ('ชาขาวอานจี๋', 'ชาขาวอานจี๋ซึ่งมีใบสีอ่อนและรสชาติหวาน เป็นหนึ่งในชาที่หายากที่สุดของจีน'),
  'quzhou/go': ('หมากล้อม (เว่ยฉี)', 'ด้วยตำนานเขาหลานเค่ออันศักดิ์สิทธิ์ เมืองนี้จึงได้รับการยกย่องว่าเป็น \'ดินแดนแห่งหมากล้อม\''),
  'quzhou/peaks': ('ภูเขาเจียงหลาง', 'เสาหินยักษ์สามต้นที่ตั้งตระหง่านเสียดฟ้าเป็นภูมิทัศน์อันเป็นเอกลักษณ์ที่ได้รับการขึ้นทะเบียนจากยูเนสโก'),
  'quzhou/ponkan': ('ส้มพอนคานฉวีโจว', 'ส้มพอนคานเปลือกหวานเป็นของขวัญฤดูหนาวจากเนินเขาที่อบอุ่น'),
  'quzhou/cake': ('ขนมปังแบนอบ', 'ขนมปังแบนงาอบกรอบที่อบบนผนังเตาเป็นอาหารเช้าคลาสสิกของท้องถิ่น'),
  'huainan/tofu': ('แหล่งกำเนิดเต้าหู้', 'เต้าหู้ถูกคิดค้นขึ้นที่ภูเขาปากงเมื่อ 2,000 ปีก่อน และแพร่หลายสู่ครัวโลกจากที่นี่'),
  'huainan/coalmine': ('เมืองถ่านหิน', 'หวยหนานอุดมไปด้วยแหล่งถ่านหิน จึงเป็นฐานพลังงานของจีนตะวันออก'),
  'huainan/oldtown': ('เมืองเก่าโช่วเซี่ยน', 'กำแพงเมืองสมัยราชวงศ์ซ่งที่ได้รับการอนุรักษ์ไว้อย่างสมบูรณ์เป็นตัวอย่างที่หาได้ยากของการออกแบบการป้องกันเมืองโบราณ'),
  'huainan/classic': ('หวยหนานจื่อ', 'คัมภีร์ปรัชญาที่รวบรวมโดยเจ้าชายหลิวอันถูกเขียนขึ้นบนดินแดนแห่งนี้'),
  'jingdezhen/porcelain': ('นครแห่งเครื่องเคลือบดินเผา', 'เมืองนี้ผลิตเครื่องเคลือบดินเผาสำหรับราชสำนักมาเป็นพันปี จึงเป็น "นครแห่งเครื่องเคลือบดินเผา" ของโลก'),
  'jingdezhen/kiln': ('เตาเผาโบราณ', 'เตาเผารูปมังกรที่ใช้ฟืนยังคงรักษางานศิลปะการเผาเครื่องเคลือบดินเผาแบบดั้งเดิมไว้'),
  'jingdezhen/bluewhite': ('เครื่องลายคราม', 'เครื่องลายครามสีขาวที่มีลวดลายสีน้ำเงินโคบอลต์เป็นเอกลักษณ์อันโด่งดังระดับโลกของเมืองนี้'),
  'jingdezhen/painting': ('จิตรกรรมเครื่องเคลือบดินเผา', 'เครื่องเคลือบดินเผาที่วาดด้วยพู่กันละเอียดโดยช่างฝีมือชั้นครูมีค่าดุจภาพวาดชั้นดี'),
  'jian/jinggang': ('เทือกเขาจิ่งกัง', 'เทือกเขาที่ปกคลุมด้วยหมอกแห่งนี้เป็นฐานที่มั่นแห่งแรกของการปฏิวัติ และเป็นหัวใจของการท่องเที่ยวเชิงปฏิวัติ'),
  'jian/torch': ('ประกายไฟปฏิวัติ', 'ดินแดนที่ให้กำเนิดวลี "ประกายไฟเพียงดวงเดียวสามารถจุดไฟทุ่งหญ้าได้" เป็นอนุสรณ์สถานทางประวัติศาสตร์'),
  'jian/academy': ('สถาบันไป๋ลู่โจว', 'สถาบันเก่าแก่พันปีบนเกาะแม่น้ำกานแห่งนี้ได้ผลิตบัณฑิตหลวงมานับไม่ถ้วน'),
  'jian/pine': ('สนจิ่งกัง', 'ต้นสนแดงที่ตั้งตระหง่านท่ามกลางสายหมอกเป็นสัญลักษณ์ของจิตวิญญาณแห่งภูเขาและความไม่ย่อท้อ'),
  'nanping/wuyi': ('ภูเขาอู่อี๋', 'ภูเขาที่ได้รับการขึ้นทะเบียนเป็นมรดกโลกจากยูเนสโกแห่งนี้ มีหน้าผาสีแดงและหุบเขาสีเขียวขจี ถือเป็นขุมทรัพย์ทางธรรมชาติและวัฒนธรรมอันล้ำค่า'),
  'nanping/rocktea': ('ชาต้าหงเผา', 'ชาอูหลงต้าหงเผาที่ปลูกบนหน้าผาแห่งนี้ ได้ชื่อว่าเป็นหนึ่งในชาที่แพงที่สุดในโลก'),
  'nanping/bambooraft': ('แพไม้ไผ่เก้าโค้ง', 'นักท่องเที่ยวสามารถล่องแพไม้ไผ่ไปตามลำธารเก้าโค้งที่ไหลผ่านหน้าผาสีแดงอันงดงาม'),
  'nanping/scholar': ('จูซี', 'จูซี ผู้ก่อตั้งลัทธิขงจื๊อใหม่ เคยสอนหนังสืออยู่ที่เชิงเขาเหล่านี้'),
  'shenzhen/skyscraper': ('ตึกระฟ้า', 'จากหมู่บ้านชาวประมงสู่ป่าตึกระฟ้าภายใน 40 ปี นี่คือปาฏิหาริย์แห่งการปฏิรูปของจีน'),
  'shenzhen/chip': ('เมืองเทคโนโลยี', 'ด้วยตลาดอิเล็กทรอนิกส์หัวเฉียงเป่ยและบริษัทเทคโนโลยียักษ์ใหญ่ เซินเจิ้นจึงได้ชื่อว่าเป็น \'ซิลิคอนแวลลีย์แห่งจีน\''),
  'shenzhen/miniature': ('หน้าต่างโลก', 'สวนสนุกที่รวบรวมสิ่งก่อสร้างจำลองของสถานที่สำคัญทั่วโลกแห่งนี้ ถือเป็นสัญลักษณ์ของเมืองเซินเจิ้น'),
  'shenzhen/mangrove': ('อ่าวเซินเจิ้น', 'อ่าวที่เต็มไปด้วยป่าชายเลนแห่งนี้เป็นแหล่งอาศัยของนกอพยพและนกกระยาง'),
  'xian/terracotta': ('กองทัพทหารดินเผา', 'ทหารดินเผานับพันนายที่เฝ้าสุสานจักรพรรดิจิ๋นซี ได้รับการขนานนามว่าเป็นสิ่งมหัศจรรย์อันดับแปดของโลก'),
  'xian/citywall': ('กำแพงเมืองซีอาน', 'กำแพงเมืองสมัยราชวงศ์หมิงที่ได้รับการอนุรักษ์ไว้อย่างดีที่สุดของจีนแห่งนี้ สามารถปั่นจักรยานเที่ยวชมได้ตลอดแนว'),
  'xian/drumtower': ('หอระฆัง', 'หอระฆังสมัยราชวงศ์หมิงที่ตั้งอยู่ใจกลางเมืองแห่งนี้ เป็นสัญลักษณ์ของเมืองหลวงโบราณ'),
  'xian/roujiamo': ('โร่วเจียหมัว', 'โร่วเจียหมัวคือเบอร์เกอร์ต้นตำรับแห่งเส้นทางสายไหม เป็นขนมปังแบนกรอบสอดไส้เนื้อปรุงรส'),
  'suzhou/garden': ('สวนโบราณซูโจว', 'สวนเหล่านี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกจากยูเนสโก มีการออกแบบอย่างประณีตด้วยสวนหิน บ่อน้ำ และศาลา'),
  'suzhou/watertown': ('เมืองน้ำ', 'ด้วยลำคลอง สะพานหิน และบ้านเรือนสีขาว ทำให้ซูโจวได้รับสมญานามว่า \'เวนิสแห่งตะวันออก\''),
  'suzhou/embroidery': ('ผ้าปักซูโจว', 'ผ้าปักไหมสองหน้าเป็นงานฝีมือเก่าแก่ของซูโจวที่มีอายุยาวนานนับพันปี'),
  'suzhou/kunqu': ('คุนฉวี่', 'อุปรากรคุนฉวี่อันงดงาม ซึ่งได้รับการยกย่องว่าเป็นมารดาแห่งอุปรากรจีนทั้งมวล มีต้นกำเนิดที่นี่'),
  'kunming/stoneforest': ('ป่าหิน', 'เสาหินปูนขนาดยักษ์ที่ถูกกัดเซาะมานานหลายล้านปี ก่อตัวเป็นเขาวงกตหินที่ดูน่าพิศวง'),
  'kunming/springcity': ('นครแห่งฤดูใบไม้ผลิ', 'ด้วยสภาพอากาศที่อบอุ่นตลอดทั้งปี คุนหมิงจึงได้ชื่อว่าเป็น "นครแห่งฤดูใบไม้ผลิ" ที่ดอกไม้ไม่เคยโรยรา'),
  'kunming/seagull': ('นกนางนวลหัวดำ', 'ทุกฤดูหนาว นกนางนวลหลายพันตัวจากไซบีเรียจะบินมายังริมทะเลสาบ ทำให้ชายฝั่งกลายเป็นสีขาว'),
  'kunming/ricenoodle': ('ก๋วยเตี๋ยวข้ามสะพาน', 'ก๋วยเตี๋ยวเส้นเล็กที่นำมาใส่ในน้ำซุปร้อนๆ ที่โต๊ะ เป็นอาหารขึ้นชื่อของยูนนาน'),
  'jinan/spring': ('นครแห่งน้ำพุ', 'น้ำพุที่มีชื่อเสียง 72 แห่งที่ผุดขึ้นจากใต้ดิน ทำให้เมืองจี่หนานได้ชื่อว่าเป็น "นครแห่งน้ำพุ"'),
  'jinan/daminglake': ('ทะเลสาบต้าหมิง', 'ทะเลสาบใจกลางเมืองที่ล้อมรอบด้วยต้นหลิวและดอกบัวแห่งนี้ ได้รับน้ำจากน้ำพุต่างๆ'),
  'jinan/buddhamountain': ('ภูเขาพันพระพุทธรูป', 'ด้วยพระพุทธรูปหลายร้อยองค์ที่แกะสลักอยู่ตามลาดเขา ภูเขาแห่งนี้จึงเป็นสถานที่แสวงบุญ'),
  'jinan/poet': ('หลี่ ชิงจ้าว', 'หลี่ ชิงจ้าว กวีหญิงผู้ยิ่งใหญ่ที่สุดของจีน ถือกำเนิดในนครแห่งน้ำพุแห่งนี้'),
  'ningbo/library': ('หอสมุดเทียนอีเกอ', 'หอสมุดเทียนอีเกอที่มีอายุ 450 ปีแห่งนี้ เป็นห้องสมุดส่วนตัวที่เก่าแก่ที่สุดที่ยังคงอยู่ของเอเชีย'),
  'ningbo/port': ('ท่าเรือหนิงโป-โจวซาน', 'ท่าเรือหนิงโป-โจวซานเป็นท่าเรือที่คึกคักที่สุดในโลกเมื่อพิจารณาจากปริมาณระวางสินค้า'),
  'ningbo/tangyuan': ('ทังหยวน', 'ทังหยวน หรือขนมบัวลอยไส้งาดำ เป็นของหวานขึ้นชื่อของเมืองนี้'),
  'ningbo/seafood': ('อาหารทะเล', 'ปลาอึ่งเหลืองและปูจากทะเลจีนตะวันออก เป็นวัตถุดิบหลักของอาหารท้องถิ่น'),
  'shijiazhuang/bridge': ('สะพานจ้าวโจว', 'สะพานโค้งหินอายุ 1,400 ปีแห่งนี้ เป็นสะพานโค้งแบบเปิดช่องว่างที่เก่าแก่ที่สุดในโลก'),
  'shijiazhuang/clifftemple': ('ภูเขาชางเหยียน', 'สะพานวัดที่แขวนอยู่ระหว่างหน้าผาแห่งนี้ เคยเป็นฉากหลังของภาพยนตร์มาแล้วนับไม่ถ้วน'),
  'shijiazhuang/redbase': ('ซีไป่โป', 'หมู่บ้านที่วางแผนก่อตั้งสาธารณรัฐประชาชนจีนแห่งนี้เป็นสถานที่ศักดิ์สิทธิ์ของการท่องเที่ยวเชิงประวัติศาสตร์การปฏิวัติ.'),
  'shijiazhuang/pharma': ('เมืองยา', 'เมืองนี้เป็นหนึ่งในผู้ผลิตยาที่ใหญ่ที่สุดของจีนและเป็นศูนย์กลางการผลิตยาปฏิชีวนะ.'),
  'taiyuan/jincitemple': ('วัดจิ้นฉือ', 'ด้วยรูปปั้นและน้ำพุที่มีอายุสามพันปี วัดจิ้นฉือจึงเป็นสวนวัดที่งดงามที่สุดในภาคเหนือของจีน.'),
  'taiyuan/coalcart': ('ดินแดนถ่านหิน', 'แหล่งถ่านหินของมณฑลชานซีขับเคลื่อนพลังงานให้จีน และไท่หยวนคือเมืองหลวงแห่งความมั่งคั่งนั้น.'),
  'taiyuan/vinegar': ('น้ำส้มสายชูหมักเก่าแก่', 'น้ำส้มสายชูหมักเก่าแก่เป็นรสเปรี้ยวที่ขาดไม่ได้ในอาหารของมณฑลชานซี.'),
  'taiyuan/twinpagoda': ('เจดีย์คู่', 'เจดีย์แปดเหลี่ยมสมัยราชวงศ์หมิงสององค์ ซึ่งเป็นสัญลักษณ์ของเมือง ตั้งตระหง่านเคียงข้างกัน.'),
  'hohhot/lamatemple': ('วัดต้าจ้าว', 'วัดพุทธนิกายทิเบตแห่งนี้มีชื่อเสียงจากพระพุทธรูปเงิน และเป็นศูนย์กลางทางจิตวิญญาณของเมือง.'),
  'hohhot/dairy': ('เมืองหลวงแห่งผลิตภัณฑ์นม', 'แบรนด์ผลิตภัณฑ์นมที่ใหญ่ที่สุดของจีนถือกำเนิดขึ้นที่นี่ เมืองนี้จึงได้ชื่อว่าเป็น "เมืองหลวงแห่งนม".'),
  'hohhot/wrestling': ('มวยปล้ำมองโกเลีย', 'มวยปล้ำบอค ซึ่งเป็นไฮไลต์ของเทศกาลนาดัม แสดงถึงพละกำลังแห่งทุ่งหญ้าสเตปป์.'),
  'hohhot/prairie': ('ทุ่งหญ้า', 'นอกเมืองออกไปคือทุ่งหญ้ามองโกเลียสีเขียวขจีที่เต็มไปด้วยม้าและฝูงสัตว์.'),
  'sanya/resortbeach': ('ชายหาดเขตร้อน', 'หาดทรายขาวละเอียดและน้ำทะเลสีฟ้าครามของอ่าวหยาหลงเปรียบเสมือนฮาวายของจีน.'),
  'sanya/guanyin': ('พระโพธิสัตว์กวนอิม', 'พระโพธิสัตว์กวนอิมองค์นี้มีความสูง 108 เมตรเหนือทะเล และเป็นหนึ่งในรูปปั้นเทพธิดาที่สูงที่สุดในโลก.'),
  'sanya/diving': ('การดำน้ำ', 'ด้วยน้ำทะเลที่อบอุ่น ใสสะอาด และแนวปะการัง ซานย่าจึงเป็นสวรรค์ของการดำน้ำของจีน.'),
  'sanya/coconutdrink': ('มะพร้าว', 'น้ำมะพร้าวสดจากสวนเขตร้อนเป็นเครื่องดื่มดับกระหายคลายร้อนของเกาะแห่งนี้.'),
  'yangzhou/slenderlake': ('ทะเลสาบซีหูผอม', 'ด้วยต้นหลิวและสะพานสีขาว ทะเลสาบที่เรียวยาวแห่งนี้งดงามราวกับภาพวาด.'),
  'yangzhou/friedrice': ('ข้าวผัดหยางโจว', 'ข้าวผัดสีทองที่คลุกเคล้ากับกุ้งและไข่ เป็นอาหารคลาสสิกที่มีชื่อเสียงระดับโลก'),
  'yangzhou/morningtea': ('ชายามเช้า', 'การรับประทานอาหารเช้าแบบหรูหราด้วยซาลาเปานึ่งและชาเป็นประเพณีของหยางโจว'),
  'yangzhou/gegarden': ('สวนเก๋อ', 'สวนไผ่ที่จำลองสี่ฤดูด้วยหิน เป็นผลงานชิ้นเอกของการออกแบบสวนคลาสสิก'),
  'weihai/navalisland': ('เกาะหลิวกง', 'เกาะแห่งนี้เป็นฐานทัพของกองเรือเป่ยหยาง และเป็นพยานประวัติศาสตร์นาวีของจีนยุคใหม่'),
  'weihai/swan': ('ทะเลสาบหงส์', 'ทุกฤดูหนาว หงส์ปากเหลืองหลายร้อยตัวจากไซบีเรียจะมาเยือนทะเลสาบชายฝั่งแห่งนี้'),
  'weihai/seacucumber': ('ปลิงทะเล', 'ปลิงทะเลที่เลี้ยงในน้ำเย็นสะอาดเป็นอาหารทะเลล้ำค่าที่สุดของเมืองนี้'),
  'weihai/cape': ('แหลมสุดตะวันออกของจีน', 'แหลมที่อยู่ทางตะวันออกสุดของจีนแห่งนี้เป็นจุดแรกที่ดวงอาทิตย์ทักทายประเทศ'),
  'handan/taichi': ('ไทเก๊ก', 'เมืองกว่างฝู ซึ่งเป็นต้นกำเนิดของไทเก๊กสายหยางและอู๋ เป็นบ้านเกิดของไท่จี๋ฉวน'),
  'handan/congtai': ('หอคอยฉงไถ', 'หอคอยดินจากอาณาจักรจ้าวโบราณแห่งนี้เป็นพยานประวัติศาสตร์กว่า 2,000 ปี'),
  'handan/idiom': ('เมืองแห่งสำนวน', 'สำนวนจีนกว่า 1,500 สำนวนถือกำเนิดขึ้นที่นี่ ทำให้หานตานเป็น "เมืองแห่งสำนวน"'),
  'handan/ciporcelain': ('เครื่องเคลือบฉือโจว', 'เครื่องเคลือบฉือโจวสีดำบนพื้นขาวเป็นงานเซรามิกพื้นบ้านคลาสสิก'),
  'daqing/oilpump': ('แหล่งน้ำมัน', 'แหล่งน้ำมันที่ใหญ่ที่สุดของจีนแห่งนี้เต็มไปด้วยเครื่องสูบน้ำมันที่ผงกหัวขึ้นลง'),
  'daqing/oilworker': ('วีรบุรุษเหล็ก', 'ความมุ่งมั่นของหวังจิ้นซี วีรบุรุษคนงานน้ำมัน เป็นจิตวิญญาณในการก่อตั้งเมืองนี้'),
  'daqing/reedlake': ('พื้นที่ชุ่มน้ำ', 'ทะเลสาบกกกว้างใหญ่ท่ามกลางบ่อน้ำมันเป็นที่อยู่อาศัยของนกกระเรียนและหงส์'),
  'daqing/hotspring': ('น้ำพุร้อน', 'น้ำแร่ร้อนจากใต้ดินมอบการพักผ่อนเพื่อบำบัดในภาคเหนือที่หนาวเย็น'),
  'zibo/bbq': ('บาร์บีคิวจือป๋อ', 'บาร์บีคิวเสียบไม้ที่ย่างบนเตาถ่านขนาดเล็กและห่อด้วยแป้งแพนเค้กบาง ๆ เป็นกระแสความนิยมที่แพร่หลายไปทั่วประเทศจีน'),
  'zibo/cuju': ('กีฬาคูจู', 'คูจู กีฬาฟุตบอลที่เก่าแก่ที่สุดในโลก มีต้นกำเนิดและถูกเล่นในเมืองหลินจือ ซึ่งเป็นเมืองหลวงโบราณของแคว้นฉี'),
  'zibo/ceramic': ('เครื่องปั้นดินเผาจือป๋อ', 'ด้วยเตาเผาที่มีอายุยาวนานนับพันปี เมืองจือป๋อจึงเป็นศูนย์กลางเครื่องปั้นดินเผาที่สำคัญแห่งหนึ่งของจีนตอนเหนือ'),
  'zibo/glass': ('เครื่องแก้วหลิวหลี', 'หลิวหลีเป็นงานฝีมือที่ทำด้วยมือจากแก้วหลอมสีสันสดใส ซึ่งเปล่งประกายงดงาม'),
  'taian/mounttai': ('ภูเขาไท่ซาน', 'ภูเขาไท่ซานเป็นหนึ่งในห้ายอดเขาศักดิ์สิทธิ์ที่สำคัญที่สุด และเป็นยอดเขาที่จักรพรรดิเคยประกอบพิธีบวงสรวงสวรรค์'),
  'taian/sunrise': ('ชมพระอาทิตย์ขึ้นบนยอดเขา', 'การได้ชมพระอาทิตย์ขึ้นเหนือทะเลหมอกเป็นรางวัลอันล้ำค่าสำหรับผู้ที่พิชิตยอดเขาไท่ซาน'),
  'taian/stonesteps': ('บันไดหินสู่ยอดเขา', 'บันไดหินกว่า 7,000 ขั้นสู่ยอดเขาเป็นบททดสอบกำลังกายของผู้แสวงบุญ'),
  'taian/daitemple': ('วัดไต้เมี่ยว', 'วัดไต้เมี่ยวอันยิ่งใหญ่ที่เชิงเขาเป็นสถานที่ที่จักรพรรดิเตรียมตัวสำหรับพิธีบวงสรวงภูเขาไท่ซาน'),
  'lianyungang/monkey': ('ภูเขาฮัวกั่วซาน', 'ภูเขาฮัวกั่วซาน ซึ่งเป็นบ้านเกิดของซุนหงอคงในเรื่องไซอิ๋ว ตั้งตระหง่านอยู่ที่นี่'),
  'lianyungang/seaport': ('ท่าเรือเหลียนหยุนกัง', 'ท่าเรือแห่งนี้เป็นประตูทางทะเลฝั่งตะวันออกของเส้นทางสายไหม และเป็นจุดสิ้นสุดฝั่งแปซิฟิกของสะพานรถไฟยูเรเชีย'),
  'lianyungang/mountain': ('ภูเขาหยุนไถ', 'ด้วยยอดเขาที่สูงชันและป่าไม้ ภูเขาหยุนไถจึงเป็นภูเขาที่สูงที่สุดในมณฑลเจียงซู'),
  'lianyungang/crystal': ('ดินแดนแห่งคริสตัล', 'เมืองตงไห่ที่อยู่ใกล้เคียงเป็นที่ตั้งของตลาดคริสตัลควอตซ์ที่ใหญ่ที่สุดแห่งหนึ่งของโลก'),
  'maanshan/libai': ('กวีหลี่ไป๋', 'เมืองริมแม่น้ำแห่งนี้เป็นจุดสุดท้ายและเป็นที่ฝังศพของหลี่ไป๋ กวีผู้ยิ่งใหญ่ที่สุดของจีน'),
  'maanshan/steel': ('เมืองเหล็กกล้า', 'โรงงานเหล็กหม่ากังทำให้เมืองนี้กลายเป็นหนึ่งในฐานอุตสาหกรรมเหล็กและเหล็กกล้าที่สำคัญของจีน'),
  'maanshan/rivercliff': ('หน้าผาไฉ่สือจี๋', 'หน้าผาที่ทอดตัวลงสู่แม่น้ำแยงซีแห่งนี้เป็นฉากกวีในตำนานของหลี่ไป๋'),
  'maanshan/moonwine': ('จันทราและสุรา', 'ดวงจันทร์และสุราในบทกวีของหลี่ไป๋ยังคงได้รับการเฉลิมฉลองในเทศกาลริมแม่น้ำ'),
  'longyan/tulou': ('ถู่โหลวหย่งติ้ง', 'บ้านดินฮากกาขนาดใหญ่รูปทรงกลมที่กระจายอยู่ตามเนินเขาเหล่านี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกจากยูเนสโก'),
  'longyan/redmeeting': ('การประชุมกู่เถียน', 'การประชุมครั้งประวัติศาสตร์ที่กำหนดทิศทางของกองทัพแดงจัดขึ้นที่หมู่บ้านแห่งนี้'),
  'longyan/hakka': ('วัฒนธรรมฮากกา', 'ชาวฮากกาซึ่งอพยพมาจากทางเหนือยังคงรักษาภาษาและอาหารของตนไว้ในแถบภูเขาเหล่านี้'),
  'longyan/mountain': ('ภูเขากวนจื้อ', 'ด้วยหน้าผาสีแดงและสระน้ำใสสะอาด ภูเขาแห่งนี้จึงเป็นไข่มุกธรรมชาติแห่งฝูเจี้ยนตอนใต้'),
  'sanming/danxia': ('ไท่หนิงตานเซี่ย', 'อุทยานธรณีโลกของยูเนสโกแห่งนี้มีหน้าผาสีแดงและหุบเหว เป็นเขาวงกตหินที่ตกลงมาจากฟากฟ้า'),
  'sanming/shaxian': ('ของว่างซาเซี่ยน', 'ด้วยเกี๊ยวราคาถูกและบะหมี่คลุก ของว่างจากซาเซี่ยนได้แพร่หลายไปทั่วประเทศจีน'),
  'sanming/forest': ('เมืองหลวงสีเขียว', 'ซานหมิงเป็นเมืองที่มีป่าไม้มากที่สุดในจีน จึงมีอากาศบริสุทธิ์และภูเขาสีเขียว'),
  'sanming/goldenlake': ('ทะเลสาบจินหู', 'ทะเลสาบแห่งนี้ทอดยาวอยู่ท่ามกลางหน้าผาตานเซี่ย และสามารถสำรวจได้ด้วยเรือ'),
  'ningde/mudflat': ('หาดโคลนเซี่ยผู่', 'หาดโคลนที่ระยิบระยับและเปลี่ยนแปลงไปตามกระแสน้ำทะเลเหล่านี้เป็นหนึ่งในชายฝั่งที่ถูกถ่ายภาพมากที่สุดในโลก'),
  'ningde/whitetea': ('ชาขาวฝูติ่ง', 'ชาขาวที่ตากแห้งพร้อมยอดอ่อนมีคุณค่ามากขึ้นเมื่อเวลาผ่านไป'),
  'ningde/taimu': ('ภูเขาไท่มู่', 'ด้วยยอดหินแกรนิตและถ้ำเหนือทะเล ภูเขาแห่งนี้จึงเป็น \'ดินแดนเทพนิยายริมทะเล\''),
  'ningde/croaker': ('ปลาจวดเหลือง', 'ปลาจวดเหลืองขนาดใหญ่ที่เลี้ยงในอ่าวที่กำบังเป็นสมบัติทางทะเลของเมืองนี้'),
  'shaoguan/redcliff': ('ภูเขาตานเซี่ย', 'ภูเขาหินสีแดงที่เป็นต้นกำเนิดของชื่อภูมิประเทศ \'ตานเซี่ย\' มีชื่อเสียงจากเสาหินแกะสลัก'),
  'shaoguan/chantemple': ('วัดหนานหัว', 'วัดแห่งนี้เป็นศูนย์กลางศักดิ์สิทธิ์ของนิกายฉาน ซึ่งเป็นวัดของฮุ่ยเหนิง ปรมาจารย์องค์ที่หกแห่งพุทธศาสนานิกายฉาน'),
  'shaoguan/ancestor': ('จูจี้เซี่ยง', 'ซอยแห่งนี้เป็นสถานที่ที่ชาวจีนตอนใต้หลายล้านคนสืบย้อนบรรพบุรุษผู้ย้ายถิ่นฐานมา'),
  'shaoguan/yaodance': ('ชาวเย้า', 'ชาวเย้าที่อาศัยอยู่ในหมู่บ้านบนภูเขาเป็นที่รู้จักจากเครื่องแต่งกายหลากสีสันและการเต้นรำกลอง'),
  'zhanjiang/oyster': ('หอยนางรมจ้านเจียง', 'หอยนางรมตัวอวบอ้วนที่เลี้ยงในน้ำอุ่นทางตอนใต้จะถูกนำไปย่างบนเตาถ่านเพื่อเสิร์ฟบนโต๊ะอาหาร'),
  'zhanjiang/navy': ('ท่าเรือทัพเรือ', 'ท่าเรือน้ำลึกแห่งนี้เป็นที่ตั้งของกองเรือทะเลใต้และเป็นประตูทางทะเลทางใต้ของประเทศ'),
  'zhanjiang/mangrove': ('ป่าชายเลน', 'ป่าชายเลนที่ใหญ่ที่สุดของจีนเป็นที่อยู่อาศัยของนกกระยางและปูในบริเวณน้ำขึ้นน้ำลง'),
  'zhanjiang/donghai': ('เกาะตงไห่', 'ด้วยชายหาดยาวและลมที่พัดสม่ำเสมอ เกาะแห่งนี้จึงเป็นที่นิยมสำหรับการอาบแดดและเล่นกระดานโต้คลื่น'),
  'maoming/lychee': ('เมืองหลวงแห่งลิ้นจี่', 'เมืองหม่าหมิงเป็นผู้ผลิตลิ้นจี่รายใหญ่ที่สุดของจีนและเป็นดินแดนที่เคยส่งลิ้นจี่ถวายจักรพรรดิ'),
  'maoming/refinery': ('ฐานปิโตรเคมี', 'โรงกลั่นที่ใหญ่ที่สุดแห่งหนึ่งในภาคใต้ของจีนขับเคลื่อนความแข็งแกร่งทางอุตสาหกรรมของเมือง'),
  'maoming/ladyxian': ('สตรีเสียน', 'สตรีเสียน วีรสตรีผู้รวมภาคใต้ให้เป็นหนึ่งเดียว ได้รับการยกย่องจากผู้คนมาเป็นเวลาพันปี'),
  'maoming/seaside': ('ชายหาด', 'ชายฝั่งยาวแห่งนี้ได้รับการขนานนามว่าเป็น "ชายหาดอันดับ 1 ของจีน" และมีหาดทรายสีทองสำหรับครอบครัว'),
  'zhaoqing/sevenstar': ('เขาเจ็ดดาว', 'เขาหินปูนเจ็ดลูกที่โผล่ขึ้นมาจากทะเลสาบถูกเรียกว่า "กุ้ยหลินแห่งกวางตุ้ง"'),
  'zhaoqing/inkstone': ('หินฝนหมึกตวน', 'หินฝนหมึกตวน ซึ่งเป็นหนึ่งในสี่สมบัติของการประดิษฐ์ตัวอักษร ได้รับการแกะสลักที่นี่มาเป็นเวลาพันปี'),
  'zhaoqing/dinghu': ('ภูเขาติ่งหู', 'เขตสงวนธรรมชาติแห่งแรกของจีนที่มีป่าฝนเขียวชอุ่มและน้ำตก เป็น "บาร์ออกซิเจน" ที่มีชีวิต'),
  'zhaoqing/songwall': ('กำแพงเมืองสมัยซ่ง', 'กำแพงเมืองสมัยซ่งที่ได้รับการอนุรักษ์ไว้อย่างสมบูรณ์ล้อมรอบเมืองจ้าวชิ่งเก่าด้วยวงกลมแห่งประวัติศาสตร์'),
  'huizhou/westlake': ('ทะเลสาบตะวันตกหุ้ยโจว', 'ทะเลสาบแห่งนี้เป็นที่รักของซูซื่อ กวีผู้ถูกเนรเทศ และเป็นบทกวีแห่งต้นหลิวและทางเดิน'),
  'huizhou/luofu': ('เขาหลัวฝู', 'เขาหลัวฝูเป็นภูเขาที่ขึ้นชื่อเรื่องฤๅษีเต๋าและสมุนไพรบำบัด และยังได้รับการยกย่องให้เป็นหนึ่งในยอดเขาศักดิ์สิทธิ์แห่งแรกของภาคใต้'),
  'huizhou/alchemy': ('วิชาเล่นแร่แปรธาตุของเก่อหง', 'เก่อหง นักเล่นแร่แปรธาตุและแพทย์ ได้เขียนรากฐานของวิชาแพทย์แผนโบราณบนภูเขาแห่งนี้'),
  'huizhou/xunliao': ('อ่าวซวิ่นเหลียว', 'อ่าวซวิ่นเหลียวมีน้ำทะเลใสและหาดทรายนุ่มละเอียด จึงเป็นรีสอร์ตชายฝั่งทางใต้ที่เงียบสงบและน่าพักผ่อน'),
  'meizhou/weilongwu': ('เมืองหลวงของชาวฮากกา', 'เมืองเหมยโจวได้รับการขนานนามว่าเป็น "เมืองหลวงของชาวฮากกาโลก" และมีชื่อเสียงจากบ้านเรือนแบบเหวยหลงอู๋ที่มีลักษณะคล้ายเกือกม้า'),
  'meizhou/saltchicken': ('ไก่เกลือ', 'ไก่เกลือเป็นอาหารขึ้นชื่อของชาวฮากกา โดยนำไก่ไปอบฝังในเกลือร้อนจนได้เนื้อที่นุ่มละมุน'),
  'meizhou/football': ('แหล่งกำเนิดฟุตบอล', 'เมืองเหมยโจวได้รับการยกย่องว่าเป็นแหล่งกำเนิดฟุตบอลจีน และได้สร้างนักฟุตบอลดาวเด่นมาหลายรุ่น'),
  'meizhou/plum': ('ดอกเหมย', 'เมืองเหมยโจวซึ่งมีชื่อหมายถึง "ดอกเหมย" จะประดับประดาไปด้วยดอกเหมยบานสะพรั่งงดงามในฤดูหนาว'),
  'jiangmen/diaolou': ('เตียวโหลวไคผิง', 'เตียวโหลวไคผิงเป็นหอคอยป้อมปราการหลายชั้นที่สร้างโดยผู้อพยพที่เดินทางกลับมา และได้รับการขึ้นทะเบียนเป็นมรดกโลกโดยยูเนสโก'),
  'jiangmen/qiaoxiang': ('ถิ่นฐานชาวจีนโพ้นทะเล', 'เมืองเจียงเหมินเป็นบ้านเกิดของชาวจีนโพ้นทะเลหลายล้านคน ซึ่งผสมผสานวัฒนธรรมตะวันออกและตะวันตกเข้าไว้ด้วยกันอย่างลงตัว'),
  'jiangmen/chenpi': ('เฉินผี', 'เฉินผี หรือเปลือกส้มซินฮุ่ยที่ผ่านการบ่ม เป็นทั้งเครื่องเทศและยาสมุนไพรล้ำค่า'),
  'jiangmen/birds': ('อุทยานนก', 'อุทยานนกแห่งนี้เป็นป่าเล็กๆ ที่เกิดจากต้นไทรยักษ์เพียงต้นเดียว และเป็นที่อยู่อาศัยของนกกระยางนับหมื่นตัว'),
  'yangjiang/knife': ('เมืองมีด', 'มีดทำครัวจำนวนมากของจีนถูกตีขึ้นที่เมืองหยางเจียงแห่งนี้ ด้วยประเพณีการตีเหล็กที่มีมานานหลายศตวรรษ'),
  'yangjiang/shipwreck': ('ซากเรือหนานไห่หมายเลข 1', 'ซากเรือหนานไห่หมายเลข 1 เป็นเรือสมัยราชวงศ์ซ่งจากเส้นทางสายไหมทางทะเล ซึ่งถูกจัดแสดงพร้อมสมบัติล้ำค่าในพิพิธภัณฑ์ใต้น้ำ'),
  'yangjiang/hailing': ('เกาะไห่หลิง', 'เกาะไห่หลิงมีชายหาดที่มีแดดจ้าและคลื่นทะเล จึงเป็นรีสอร์ตริมทะเลที่ได้รับความนิยมที่สุดของมณฑลกวางตุ้ง'),
  'yangjiang/kite': ('เมืองว่าว', 'เมืองหยางเจียงเป็นหนึ่งในสองเมืองหลวงแห่งว่าวของจีนเคียงคู่กับเมืองเหวยฟาง ซึ่งว่าวจะเต็มท้องฟ้าในฤดูใบไม้ร่วง'),
  'qingyuan/rafting': ('แหล่งล่องแก่ง', 'เมืองชิงหยวนขึ้นชื่อว่าเป็น \'บ้านแห่งการล่องแก่ง\' ของจีน ด้วยลำธารภูเขาที่ไหลเชี่ยว'),
  'qingyuan/chicken': ('ไก่ชิงหยวน', 'ไก่พื้นเมืองพันธุ์นี้มีกระดูกเล็กและรสชาติอร่อย เป็นที่ต้องการมากที่สุดในอาหารกวางตุ้ง'),
  'qingyuan/hotspring': ('น้ำพุร้อน', 'น้ำแร่ร้อนจากหุบเขาเป็นศูนย์กลางของการพักผ่อนช่วงวันหยุดสุดสัปดาห์'),
  'qingyuan/yaoterrace': ('นาขั้นบันไดเผ่าเย้า', 'นาขั้นบันไดที่แกะสลักบนเนินเขาโดยชาวเย้าแห่งเหลียนหนานเป็นบันไดแห่งการทำงานหนักนับศตวรรษ'),
  'chaozhou/guangjibridge': ('สะพานกวงจี้', 'สะพานโบราณที่สามารถเปิดปิดได้ตรงกลางเพื่อให้เรือผ่าน เป็นหนึ่งในสี่สะพานที่มีชื่อเสียงของจีน'),
  'chaozhou/woodcarving': ('งานแกะสลักไม้ปิดทอง', 'งานแกะสลักไม้หลายชั้นที่ปิดทองคำเปลวทำให้วัดวาอารามส่องประกายระยิบระยับ'),
  'chaozhou/chaoxiu': ('ผ้าปักเฉาโจว', 'ด้วยการปักด้ายทองคำแบบนูน ผ้าปักเฉาโจวจึงเป็นงานปักที่หรูหราที่สุดในภาคใต้ของจีน'),
  'chaozhou/kaiyuan': ('วัดไคหยวน', 'วัดเก่าแก่ 1,200 ปีแห่งนี้มีลานภายในที่สงบเงียบแบบราชวงศ์ถัง และเป็นหัวใจของเมือง'),
  'jieyang/citygate': ('ประตูจิ้นเซียน', 'ประตูหอคอยไม้ที่สง่างามเหนือแม่น้ำเป็นสัญลักษณ์ที่ยังคงหลงเหลืออยู่ของเมืองเจียหยางเก่า'),
  'jieyang/jade': ('เมืองหลวงแห่งหยก', 'เมืองหยางเหมยเป็นหนึ่งในศูนย์กลางการแกะสลักและค้าขายหยกที่ใหญ่ที่สุดของจีน'),
  'jieyang/jieyanglou': ('หอเจียหยาง', 'หอคอยขนาดใหญ่ที่มีชายคาแบบดั้งเดิมนี้เป็นอนุสาวรีย์สมัยใหม่ที่แสดงถึงวัฒนธรรมเฉาซาน'),
  'jieyang/beefbroth': ('ซุปเนื้อเฉาซาน', 'เนื้อวัวสดลวกในน้ำซุปใสเป็นอาหารขึ้นชื่อของภูมิภาคนี้'),
  'yunfu/marble': ('อาณาจักรหิน', 'หยุนฝูเป็นเมืองหลวงแห่งหินอ่อนและงานหิน โดยส่งออกหินขัดเงาไปทั่วโลก'),
  'yunfu/patriarch': ('ปรมาจารย์องค์ที่หก', 'ดินแดนแห่งนี้เป็นบ้านเกิดของปรมาจารย์เซนฮุ่ยเหนิง และได้รับการสักการะโดยวัดกั๋วเอิน'),
  'yunfu/tianlu': ('ภูเขาเทียนลู่', 'ด้วยยอดเขาที่ปกคลุมด้วยเมฆและไร่ชา ภูเขาแห่งนี้จึงเป็นมงกุฎสีเขียวของเมือง'),
  'yunfu/xijiang': ('แม่น้ำซีเจียง', 'แม่น้ำซีเจียงเป็นสาขาหลักของแม่น้ำจูเจียง ซึ่งเป็นเส้นทางน้ำสำคัญทางใต้ที่ไหลผ่านเมืองนี้'),
  'liuzhou/luosifen': ('หลัวซือเฝิ่น', 'หลัวซือเฝิ่นเป็นก๋วยเตี๋ยวเส้นหมี่หอยทากรสจัดจ้าน เปรี้ยวเผ็ดร้อน ที่กำลังเป็นที่นิยมไปทั่วประเทศจีน'),
  'liuzhou/autocity': ('เมืองยานยนต์', 'หลิ่วโจวเป็นหนึ่งในฐานการผลิตยานยนต์ที่ใหญ่ที่สุดของจีน โดยเฉพาะรถยนต์ขนาดเล็กที่ผู้คนชื่นชอบ'),
  'liuzhou/karst': ('ภูมิประเทศคาสต์แม่น้ำหลิ่ว', 'เนินเขาหินปูนและแม่น้ำที่โอบล้อมเมืองช่วยเพิ่มความงามตามธรรมชาติให้กับเมืองอุตสาหกรรมแห่งนี้'),
  'liuzhou/liuhou': ('หลิวจงหยวน', 'อนุสรณ์ของหลิวจงหยวน กวีและผู้ว่าการในสมัยราชวงศ์ถัง ยังคงอยู่ในศาลเจ้าภายในสวนสาธารณะของเมือง'),
  'wuzhou/gemstone': ('เมืองหลวงแห่งอัญมณี', 'อัญมณีสังเคราะห์จำนวนมากของโลกถูกเจียระไนในโรงงานของเมืองริมแม่น้ำแห่งนี้'),
  'wuzhou/liubaotea': ('ชาหลิ่วเป่า', 'ชาดำหลิ่วเป่าที่บ่มแล้วเป็นเครื่องดื่มคลาสสิกช่วยย่อยอาหารของภาคใต้ที่มีอากาศชื้น'),
  'wuzhou/turtlejelly': ('กุยหลิงเกา', 'กุยหลิงเกาเป็นเยลลี่สมุนไพรสีดำรสขมที่ช่วยคลายร้อนได้ดีในวันอากาศร้อน'),
  'wuzhou/dragonmother': ('ศาลเจ้าแม่มังกร', 'ศาลเจ้าแห่งนี้อุทิศให้กับเจ้าแม่มังกร ซึ่งเป็นเทพธิดาแห่งแม่น้ำและเป็นที่ศรัทธามาอย่างยาวนานของชาวประมง'),
  'beihai/silverbeach': ('หาดเงิน', 'หาดเงินซึ่งมีทรายขาวละเอียดระยิบระยับ ได้รับการขนานนามว่าเป็น \'ชายหาดอันดับหนึ่งใต้ฟ้า\' และทอดยาวหลายไมล์'),
  'beihai/pearl': ('เมืองไข่มุก', 'ไข่มุกทะเลใต้จากเหอผู่ได้รับการยกย่องว่าเป็นไข่มุกที่ดีที่สุดมาตั้งแต่สมัยบรรณาการของจักรพรรดิ'),
  'beihai/weizhou': ('เกาะเวยโจว', 'เกาะเวยโจวเป็นเกาะภูเขาไฟที่อายุน้อยที่สุดของจีน ดึงดูดนักดำน้ำด้วยหน้าผาสีดำและปะการัง'),
  'beihai/oldstreet': ('ถนนเก่า', 'อาคารสไตล์โคโลเนียลที่มีเสาเรียงรายอายุนับร้อยปี ยังคงรักษาอดีตของท่าเรือเส้นทางสายไหมทางทะเลไว้ได้'),
  'qinzhou/nixingpottery': ('เครื่องปั้นดินเผาหนีซิง', 'เครื่องปั้นดินเผาหนีซิง ซึ่งเปลี่ยนสีได้เองในเตาเผา เป็นหนึ่งในสี่เครื่องปั้นดินเผาที่มีชื่อเสียงของจีน'),
  'qinzhou/dolphin': ('โลมาขาว', 'โลมาขาวจีนหายากที่ว่ายอยู่ในอ่าวซานเหนียงเป็นสัญลักษณ์อันเป็นที่รักของเมืองนี้'),
  'qinzhou/oysterfarm': ('แหล่งเลี้ยงหอยนางรม', 'หอยนางรมยักษ์ที่เลี้ยงในอ่าวตื้นเขินทำให้เมืองชินโจวเป็นเมืองหลวงแห่งหอยนางรมของจีน'),
  'qinzhou/general': ('นายพลเฟิง จื่อไฉ', 'เมืองนี้เป็นบ้านเกิดของนายพลเฟิง จื่อไฉ วีรบุรุษผู้สูงวัยที่ปกป้องชายแดน จึงเต็มไปด้วยความทรงจำอันกล้าหาญ'),
  'guigang/lotus': ('เมืองบัว', 'ด้วยทุ่งดอกบัวอันกว้างใหญ่ที่บานสะพรั่งตลอดฤดูร้อน เมืองกุ้ยก่างจึงได้ชื่อว่าเป็น "เมืองบัว"'),
  'guigang/uprising': ('การก่อการกำเริบจินเทียน', 'ประกายไฟแรกของการก่อการกำเริบไท่ผิงที่สั่นสะเทือนประวัติศาสตร์ได้เริ่มต้นขึ้นบนผืนแผ่นดินแห่งนี้'),
  'guigang/nanshan': ('วัดหนานซาน', 'วัดถ้ำอายุนับพันปีที่แกะสลักเข้าไปในหินแห่งนี้ประดับประดาด้วยจารึกของจักรพรรดิ'),
  'guigang/sugarcane': ('อ้อย', 'ที่ราบลุ่มแม่น้ำอันอุดมสมบูรณ์แห่งนี้เป็นแหล่งผลิตน้ำตาลที่ใหญ่ที่สุดของจีน'),
  'yulin/medicine': ('ตลาดสมุนไพร', 'ตลาดสมุนไพรที่ใหญ่ที่สุดในภาคใต้ของจีนแห่งนี้รวบรวมสมุนไพรบำบัดนับพันชนิด'),
  'yulin/goldenpalace': ('วังหยุนเทียน', 'วังวัฒนธรรมขนาดมหึมาที่หุ้มด้วยทองคำแห่งนี้สร้างความตื่นตาตื่นใจด้วยรูปปั้นและโถงอันยิ่งใหญ่'),
  'yulin/lychee': ('สวนลิ้นจี่', 'ลิ้นจี่หวานที่ปลูกบนเนินเขาอบอุ่นเป็นสมบัติสีแดงของตลาดฤดูร้อน'),
  'yulin/beef': ('เนื้อหนิวปา', 'เนื้อหนิวปาที่ปรุงรสด้วยเครื่องเทศเป็นของว่างขึ้นชื่อเก่าแก่ของภูมิภาคนี้'),
  'baise/redbase': ('การก่อการกำเริบไป๋เซ่อ', 'การก่อการกำเริบที่นำโดยเติ้ง เสี่ยวผิง ในวัยหนุ่มถือเป็นจุดเปลี่ยนสำคัญในประวัติศาสตร์คอมมิวนิสต์'),
  'baise/sinkhole': ('หลุมยุบเล่อเย่', 'กลุ่มหลุมยุบขนาดยักษ์ที่ใหญ่ที่สุดในโลกแห่งนี้ซ่อนป่าไม้ไว้ในความลึกของมัน'),
  'baise/mango': ('เมืองหลวงแห่งมะม่วง', 'ด้วยหุบเขาที่ร้อนระอุ เมืองไป๋เซ่อจึงเป็นแหล่งปลูกมะม่วงที่ใหญ่ที่สุดของจีน'),
  'baise/aluminum': ('เมืองอะลูมิเนียม', 'เมืองนี้อุดมไปด้วยแร่บอกไซต์ จึงเป็นฐานอุตสาหกรรมอะลูมิเนียมทางใต้ของจีน'),
  'hechi/longevity': ('ปาหม่า ดินแดนแห่งผู้มีอายุยืน', 'ด้วยผู้คนที่อาศัยอยู่เกินร้อยปี ปาหม่าจึงเป็น "ดินแดนแห่งผู้มีอายุยืน" ที่มีชื่อเสียงระดับโลก'),
  'hechi/folksong': ('หลิวซานเจี่ย', 'ตำนานนางฟ้าเพลงหลิวซานเจี่ยยังคงสืบทอดผ่านการประกวดร้องเพลงโต้ตอบ'),
  'hechi/bronzedrum': ('กลองสำริด', 'กลองสำริดศักดิ์สิทธิ์ของชาวจ้วงและชาวเขาจำนวนมากที่สุดรวมตัวกันอยู่ที่นี่'),
  'hechi/geopark': ('อุทยานธรณีคาสต์', 'ด้วยหลุมยุบ ถ้ำ และแม่น้ำใต้ดิน ภูมิภาคนี้จึงเป็นดินแดนมหัศจรรย์แห่งหินปูนคาสต์'),
  'laibin/sugarcity': ('เมืองหลวงแห่งน้ำตาล', 'ด้วยทุ่งอ้อยที่กว้างใหญ่ไพศาล ไหลปินจึงได้รับการขนานนามว่าเป็น \'เมืองน้ำตาลของจีน\''),
  'laibin/yao': ('ชาวเย้าต้าเหยา', 'ชาวเย้าแห่งเทือกเขาต้าเหยาในจินซิ่ว ซึ่งแบ่งออกเป็นห้าสาขาที่แตกต่างกัน ถือเป็นสมบัติทางวัฒนธรรมอันล้ำค่า'),
  'laibin/hongshui': ('แม่น้ำหงสุ่ย', 'แม่น้ำหงสุ่ยอันยิ่งใหญ่ที่กัดเซาะหุบเขา หล่อเลี้ยงภูมิภาคนี้ด้วยเขื่อนและทิวทัศน์อันงดงาม'),
  'laibin/shengtang': ('ภูเขาเซิ่งถัง', 'ด้วยทะเลหมอกและน้ำตก ภูเขาแห่งนี้คือยอดเขาที่สูงที่สุดของเทือกเขาต้าเหยา'),
  'chongzuo/waterfall': ('น้ำตกเต๋อเทียน', 'น้ำตกเต๋อเทียนตั้งอยู่บริเวณชายแดนเวียดนาม เป็นน้ำตกข้ามชาติที่ใหญ่ที่สุดในเอเชีย'),
  'chongzuo/langur': ('ค่างหัวขาว', 'ค่างหัวขาวหายากที่อาศัยอยู่เฉพาะในเนินเขาหินปูนเหล่านี้ เป็นหนึ่งในลิงที่ใกล้สูญพันธุ์มากที่สุดในโลก'),
  'chongzuo/rockart': ('ศิลปะบนหินฮวาซาน', 'ภาพเขียนสีแดงบนหน้าผาจั่วเจียงเมื่อ 2,000 ปีก่อนได้รับการขึ้นทะเบียนเป็นมรดกโลกโดยยูเนสโก'),
  'chongzuo/borderpass': ('ด่านมิตรภาพ', 'ประตูชายแดนประวัติศาสตร์สู่เวียดนามแห่งนี้เป็นด่านทางบกของเส้นทางสายไหมทางใต้'),
  'beijing/great-wall': ('กำแพงเมืองจีน', 'กำแพงป้องกันที่ยาวที่สุดในโลกกว่า 20,000 กิโลเมตร สร้างขึ้นตลอดหลายศตวรรษเพื่อปกป้องพรมแดนทางเหนือของจีน โดยส่วนปาต้าหลิงใกล้กรุงปักกิ่งที่มีบันไดหินและหอสังเกตการณ์บนสันเขาเป็นส่วนที่ได้รับความนิยมมากที่สุด'),
  'beijing/temple': ('หอสักการะฟ้าเทียนถาน', 'หมู่สิ่งก่อสร้างศักดิ์สิทธิ์ที่จักรพรรดิราชวงศ์หมิงและชิงใช้ประกอบพิธีบวงสรวงสวรรค์เพื่อขอพรให้พืชผลอุดมสมบูรณ์ทุกปี โดยหลังคาทรงกลมสีน้ำเงินสามชั้นที่สร้างขึ้นโดยไม่ใช้ตะปูแม้แต่ตัวเดียวถือเป็นหนึ่งในสัญลักษณ์ที่โดดเด่นที่สุดของสถาปัตยกรรมจีน'),
  'beijing/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์อิฐสูงประมาณ 57 เมตร 13 ชั้นจากราชวงศ์เหลียว ด้วยลวดลายแกะสลักและรูปทรงแปดเหลี่ยม ทำให้เป็นหนึ่งในสิ่งก่อสร้างที่เก่าแก่ที่สุดที่ยังคงหลงเหลืออยู่ในปักกิ่ง และเป็นพยานประวัติศาสตร์กว่าพันปีของเมือง'),
  'beijing/opera': ('อุปรากรปักกิ่ง', 'การแสดงละครจีนโบราณที่มีอายุ 200 ปี ผสมผสานการร้องเพลง การพูด ศิลปะการต่อสู้ และกายกรรม โดยใบหน้าที่แต่งแต้มสีสัน (เหลียนผู่) ของนักแสดงจะเผยให้เห็นถึงลักษณะตัวละครแต่ละตัว เช่น สีแดงหมายถึงความซื่อสัตย์ และสีขาวหมายถึงความเจ้าเล่ห์'),
  'zunyi/huiyi': ('สถานที่ประชุมจุนอี้', 'บ้านที่ใช้จัดการประชุมในปี ค.ศ. 1935 ซึ่งถือเป็นจุดเปลี่ยนสำคัญทางประวัติศาสตร์การปฏิวัติจีน'),
  'zunyi/moutai': ('เมืองเหมาไถ', 'เมืองริมฝั่งแม่น้ำชื่อสุ่ยแห่งนี้เป็นแหล่งผลิตเหล้าเหมาไถ เหล้าขาวระดับตำนานที่ได้รับการยกย่องว่าเป็นเครื่องดื่มประจำชาติจีน'),
  'zunyi/loushan': ('ช่องเขาโหลวซาน', 'ช่องเขาที่ตั้งอยู่ท่ามกลางหุบเขาสูงชันแห่งนี้เป็นสมรภูมิประวัติศาสตร์ที่ถูกนำไปบรรยายไว้ในบทกวีอันโด่งดังของเหมาเจ๋อตง'),
  'zunyi/chishui': ('น้ำตกชื่อสุ่ย', 'น้ำตกที่ไหลผ่านหน้าผาสีแดงและป่าไผ่เขียวขจี สร้างทัศนียภาพอันงดงามให้กับหุบเขาแห่งแม่น้ำสีแดง'),
  'liupanshui/coolcity': ('เมืองแห่งความเย็นสบาย', 'ด้วยอุณหภูมิในฤดูร้อนที่ไม่ค่อยเกิน 19 องศาเซลเซียส ทำให้ลิ่วพานสุ่ยได้รับฉายาว่าเป็นเมืองหลวงแห่งความเย็นสบายของจีน'),
  'liupanshui/coal': ('ทะเลถ่านหินแห่งภาคตะวันตกเฉียงใต้', 'ด้วยแหล่งถ่านหินที่อุดมสมบูรณ์ ทำให้เมืองนี้เปรียบเสมือนเตาหลอมพลังงานหลักของภาคตะวันตกเฉียงใต้ของจีน'),
  'liupanshui/grassland': ('ทุ่งหญ้าอูเหมิง', 'ทุ่งหญ้าบนที่ราบสูงอันกว้างใหญ่ที่เต็มไปด้วยฝูงม้าและกังหันลมผลิตไฟฟ้า'),
  'liupanshui/kiwi': ('กีวีไส้แดง', 'กีวีไส้แดงที่ปลูกบนที่ราบสูงอากาศเย็นถือเป็นผลไม้รสหวานที่เป็นสมบัติล้ำค่าของเมืองนี้'),
  'anshun/huangguoshu': ('น้ำตกหวงกั่วซู่', 'น้ำตกที่ใหญ่ที่สุดในเอเชียซึ่งมีความสูงถึง 77 เมตร โดยละอองน้ำที่ฟุ้งกระจายมักจะทำให้เกิดสายรุ้งที่สวยงาม'),
  'anshun/dixi': ('งิ้วพื้นบ้านตี้ซี่', 'การแสดงงิ้วที่สวมหน้ากากนักรบไม้ในลานหมู่บ้าน ซึ่งได้รับการขนานนามว่าเป็นฟอสซิลที่มีชีวิตของศิลปะงิ้วจีน'),
  'anshun/batik': ('ผ้าบาติก', 'ผ้าเขียนเทียนย้อมสีครามที่เป็นงานฝีมืออันเป็นเอกลักษณ์ของหญิงชาวเผ่าปู้อีและชาวเผ่าม้งในอันซุ่น'),
  'anshun/tunpu': ('หมู่บ้านถุนผู่', 'หมู่บ้านป้อมปราการหินของกองทัพสมัยราชวงศ์หมิงที่ยังคงรักษาการแต่งกายและภาษาถิ่นดั้งเดิมไว้นานกว่า 600 ปี'),
  'bijie/azalea': ('ทุ่งดอกอาซาเลียร้อยลี้', 'ทะเลดอกอาซาเลียที่บานสะพรั่งเต็มแนวสันเขาในทุกฤดูใบไม้ผลิ ถือเป็นสวนดอกไม้ธรรมชาติที่ใหญ่ที่สุดในโลก'),
  'bijie/zhijin': ('ถ้ำจือจิน', 'ถ้ำที่เต็มไปด้วยหินงอกหินย้อยขนาดมหึมาจนได้รับฉายาว่าเป็นพระราชวังใต้ดินที่งดงามที่สุดในจีน'),
  'bijie/caohai': ('นกกระเรียนทะเลสาบเฉ่าไห่', 'ทะเลสาบน้ำตื้นในอำเภอเวยหนิงแห่งนี้เป็นที่อยู่อาศัยในช่วงฤดูหนาวของนกกระเรียนคอดำที่หายาก'),
  'bijie/potato': ('มันฝรั่งเมืองปี้เจี๋ย', 'มันฝรั่งจากที่ราบสูงทำให้เมืองปี้เจี๋ยกลายเป็นแหล่งผลิตมันฝรั่งที่สำคัญของจีน โดยเฉพาะมันฝรั่งจากอำเภอเว่ยหนิงที่มีชื่อเสียงไปทั่วประเทศ'),
  'qujing/rapeseed': ('ทุ่งดอกเรปซีดหลัวผิง', 'ในทุกเดือนกุมภาพันธ์ ทุ่งดอกเรปซีดสีเหลืองอร่ามที่หลัวผิงจะดึงดูดทั้งผู้เลี้ยงผึ้งและช่างภาพให้มาเยือน'),
  'qujing/ham': ('แฮมซวนเวย์', 'แฮมซวนเวย์ผ่านกรรมวิธีหมักเกลือมานานหลายศตวรรษ จนกลายเป็นอาหารขึ้นชื่อที่เป็นความภาคภูมิใจของมณฑลยูนนาน'),
  'qujing/jiulong': ('น้ำตกจิ่วหลง', 'น้ำตกจิ่วหลงประกอบด้วยชั้นน้ำตกสิบชั้นที่ลดหลั่นกันลงมา ถือเป็นกลุ่มน้ำตกที่สวยงามที่สุดแห่งหนึ่งของจีน'),
  'qujing/sandforest': ('ป่าทรายหลากสี', 'เสาทรายหลากสีที่ถูกลมกัดเซาะจนกลายเป็นรูปทรงแปลกตาในอำเภอหลู่เหลียง เปรียบเสมือนสวนประติมากรรมที่ธรรมชาติสร้างขึ้น'),
  'yuxi/fuxian': ('ทะเลสาบฝูเซียน', 'ทะเลสาบที่ลึกเป็นอันดับสองของจีนแห่งนี้เปรียบเสมือนกระจกเงาบนภูเขาที่มีน้ำใสสะอาดตา'),
  'yuxi/nieer': ('เนี่ยเอ๋อร์', 'เมืองอวี้ซีเป็นบ้านเกิดของเนี่ยเอ๋อร์ ผู้ประพันธ์เพลงชาติจีน ซึ่งเมืองได้สร้างสวนดนตรีและอนุสรณ์สถานเพื่อรำลึกถึงเขา'),
  'yuxi/chengjiang': ('แหล่งฟอสซิลเฉิงเจียง', 'แหล่งฟอสซิลยุคแคมเบรียนที่มีอายุเก่าแก่กว่า 530 ล้านปีแห่งนี้เป็นมรดกโลกที่แสดงให้เห็นถึงจุดเริ่มต้นของสิ่งมีชีวิต'),
  'yuxi/kiln': ('เตาเผาอวี้ซี', 'เตาเผาโบราณสมัยราชวงศ์หยวนแห่งนี้เป็นจุดกำเนิดของเครื่องเคลือบสีน้ำเงินขาวอันเลื่องชื่อของยูนนาน'),
  'dali/threepagodas': ('เจดีย์สามองค์', 'เจดีย์สามองค์ที่ตั้งตระหง่านอยู่เชิงเขาชางซานมานานนับพันปี ถือเป็นสัญลักษณ์สำคัญของอาณาจักรต้าหลี่โบราณ'),
  'dali/erhai': ('ทะเลสาบเอ๋อไห่', 'ทะเลสาบบนภูเขาที่มีรูปร่างคล้ายหูแห่งนี้ เปรียบเสมือนภาพวาดที่มีเรือประมงและหมู่บ้านริมน้ำเป็นองค์ประกอบ'),
  'dali/cangshan': ('เทือกเขาชางซาน', 'เทือกเขาชางซานที่มียอดเขาปกคลุมด้วยหิมะถึง 19 ยอด ทอดตัวยาวเปรียบเสมือนม่านสีเขียวที่โอบล้อมเมืองต้าหลี่ไว้'),
  'dali/wind': ('ลม ดอกไม้ หิมะ จันทร์', 'ลมแห่งเซี่ยกวน ดอกไม้แห่งซ่างกวน หิมะแห่งชางซาน และจันทร์แห่งเอ๋อไห่ คือสี่ความงามของต้าหลี่ที่เปรียบได้กับบทกวี'),
  'lijiang/oldtown': ('เมืองเก่าลี่เจียง', 'เมืองมรดกโลกที่เต็มไปด้วยลำคลองและบ้านไม้หลังคากระเบื้องแห่งนี้ คือหัวใจสำคัญที่ยังมีชีวิตของวัฒนธรรมชาวน่าซี'),
  'lijiang/snowmountain': ('ภูเขาหิมะมังกรหยก', 'ยอดเขาสูง 5,596 เมตรที่ปกคลุมด้วยธารน้ำแข็งแห่งนี้ ทอดตัวตระหง่านเหนือเมืองราวกับมังกรหยกที่กำลังนอนหลับใหล'),
  'lijiang/dongba': ('อักษรตงปา', 'อักษรตงปาเป็นอักษรภาพของนักบวชชาวน่าซีที่ยังคงมีการใช้งานอยู่เพียงแห่งเดียวในโลก'),
  'lijiang/tigerleaping': ('ช่องแคบเสือกระโจน', 'ช่องแคบที่เล่าขานกันว่ามีเสือกระโดดข้ามได้แห่งนี้ เป็นหนึ่งในหุบเขาที่ลึกที่สุดในโลก'),
  'lincang/dianhong': ('ชาดำเตียนหง', 'ชาดำยอดทองจากอำเภอเฟิ่งชิ่งที่สร้างชื่อเสียงให้กับมณฑลยูนนานไปทั่วโลก'),
  'lincang/wadrum': ('กลองไม้ชาวว้า', 'เสียงกลองไม้ศักดิ์สิทธิ์ของชาวว้าดังกึกก้องไปทั่วหมู่บ้านบนเขาพร้อมกับการร่ายรำสะบัดผมอันเป็นเอกลักษณ์'),
  'lincang/teatrees': ('ต้นชาโบราณ', 'หลินชางเป็นแหล่งอนุรักษ์ป่าชาโบราณที่มีอายุหลายพันปี ซึ่งถือเป็นต้นกำเนิดของชาในโลก'),
  'lincang/lancang': ('แม่น้ำล้านช้าง', 'แม่น้ำล้านช้างหรือต้นกำเนิดของแม่น้ำโขงไหลผ่านหุบเขาทางตอนใต้และเป็นที่ตั้งของเขื่อนขนาดใหญ่หลายแห่ง'),
  'puer/tea': ('ชาผูเอ่อร์', 'ชาผูเอ่อร์แบบอัดก้อนที่มีรสชาติกลมกล่อมขึ้นตามกาลเวลา เป็นสมบัติล้ำค่าที่ตั้งชื่อตามเมืองแห่งนี้'),
  'puer/coffee': ('เมืองหลวงแห่งกาแฟของจีน', 'พื้นที่กว่าครึ่งหนึ่งของกาแฟในจีนปลูกบนเนินเขาที่ปกคลุมด้วยหมอกในเมืองผูเอ่อร์จนอบอวลไปด้วยกลิ่นหอมของกาแฟ'),
  'puer/teahorse': ('เส้นทางสายชาและม้า', 'เส้นทางโบราณที่กองคาราวานม้าใช้ขนส่งชาไปยังทิเบตเริ่มต้นขึ้นที่เมืองผูเอ่อร์และทอดยาวขึ้นสู่ยอดเขาสูง'),
  'puer/peafowl': ('นกยูงเขียว', 'ป่าเขตร้อนที่อุดมสมบูรณ์เป็นที่อยู่อาศัยของนกยูงเขียวหายากซึ่งถือเป็นอัญมณีแห่งธรรมชาติของเมืองนี้'),
  'baoshan/volcano': ('ภูเขาไฟเถิงชง', 'กรวยภูเขาไฟที่ดับแล้วกว่า 97 แห่งทำให้ที่ราบเถิงชงมีภูมิประเทศที่ดูแปลกตาคล้ายกับพื้นผิวดวงจันทร์'),
  'baoshan/rehai': ('หุบเขาเร่อไห่', 'หุบเขาที่มีน้ำพุร้อนเดือดพล่านจนสามารถนำไข่ไปต้มในบ่อน้ำร้อนธรรมชาติได้'),
  'baoshan/heshun': ('เมืองโบราณเหอซุ่น', 'เมืองหินของเหล่าพ่อค้าที่เคยเดินทางไปค้าขายต่างแดนและเป็นที่ตั้งของห้องสมุดหมู่บ้านที่เก่าแก่ที่สุดในจีน'),
  'baoshan/gaoligong': ('เทือกเขาเกาลี่กง', 'เทือกเขาเกาลี่กงเป็นขุมทรัพย์ทางธรรมชาติที่เต็มไปด้วยความหลากหลายทางชีวภาพ ทั้งหุบเขาผีเสื้อและป่าดิบชื้น'),
  'deyang/sanxingdui': ('แหล่งโบราณคดีซานซิงตุย', 'หน้ากากสำริดขนาดใหญ่ที่มีดวงตาโปนโตได้เผยให้เห็นถึงอารยธรรมสู่ที่ลึกลับซึ่งมีอายุเก่าแก่กว่า 3,000 ปี'),
  'deyang/jiannanchun': ('เหล้าเจี้ยนหนานชุน', 'เหล้าไป๋จิ่วจากเมืองเหมียนจู๋ที่มีประวัติการกลั่นยาวนานกว่า 1,500 ปี และเคยเป็นเครื่องดื่มในราชสำนักสมัยราชวงศ์ถัง'),
  'deyang/nianhua': ('ภาพพิมพ์ปีใหม่เหมียนจู๋', 'ภาพพิมพ์ไม้แกะสลักลงสีด้วยมือที่ใช้ประดับประตูบ้านเพื่อความเป็นสิริมงคลและเพิ่มสีสันในช่วงเทศกาล'),
  'deyang/turbine': ('เมืองหลวงแห่งอุตสาหกรรมหนัก', 'เต๋อหยางเป็นฐานการผลิตกังหันและเครื่องกำเนิดไฟฟ้าขนาดใหญ่ส่วนใหญ่ของประเทศจีน'),
  'mianyang/libai': ('บ้านเกิดของหลี่ไป๋', 'หลี่ไป๋ กวีเอกผู้เป็นอมตะเติบโตขึ้นท่ามกลางขุนเขาในอำเภอเจียงโหยว ซึ่งบทกวีของเขายังคงดังก้องอยู่ในความทรงจำของผู้คนจนถึงทุกวันนี้'),
  'mianyang/sciencecity': ('เมืองแห่งวิทยาศาสตร์', 'เหมียนหยางเป็นเมืองเดียวในจีนที่ได้รับสมญานามว่าเป็นเมืองแห่งวิทยาศาสตร์และเทคโนโลยี ซึ่งเป็นศูนย์กลางการวิจัยและพัฒนาที่สำคัญของประเทศ'),
  'mianyang/qiang': ('หอคอยหินชาวเชียง', 'หอคอยหินโบราณของชาวเชียงในหมู่บ้านบนภูเขาของอำเภอเป่ยชวนตั้งตระหง่านผ่านกาลเวลามานานหลายศตวรรษ'),
  'mianyang/mifen': ('เส้นหมี่เหมียนหยาง', 'เส้นหมี่เหนียวนุ่มในน้ำซุปไก่และเครื่องในรสชาติเข้มข้น คืออาหารเช้าที่เป็นเอกลักษณ์ของชาวเมืองนี้'),
  'nanchong/langzhong': ('เมืองโบราณหลางจง', 'เมืองโบราณที่ได้รับการอนุรักษ์ไว้อย่างสมบูรณ์ที่สุดตามหลักฮวงจุ้ย ตั้งอยู่ท่ามกลางโค้งน้ำที่สวยงาม'),
  'nanchong/silk': ('เมืองหลวงแห่งผ้าไหม', 'ด้วยประวัติศาสตร์การทอผ้าที่ยาวนานกว่าสองพันปี หนานชงจึงได้รับการยกย่องให้เป็นเมืองหลวงแห่งผ้าไหมทางภาคตะวันตกของจีน'),
  'nanchong/zhangfei': ('เนื้อวัวจางเฟย', 'เนื้อวัวหมักเครื่องเทศรสเลิศจากเมืองที่วีรบุรุษสามก๊กอย่างจางเฟยเคยปกครอง จึงเป็นที่มาของชื่อเรียกนี้'),
  'nanchong/zhude': ('บ้านเกิดของจูเต๋อ', 'บ้านพักเรียบง่ายของจอมพลจูเต๋อในอำเภออี๋หลง เป็นสถานที่สำคัญทางประวัติศาสตร์ที่ผู้คนนิยมมาเยี่ยมชม'),
  'yibin/wuliangye': ('เหล้าอู่เหลียงเย่', 'เหล้าไป๋จิ่วชั้นเลิศที่กลั่นจากธัญพืชห้าชนิด ถือเป็นหนึ่งในแบรนด์เหล้าที่มีชื่อเสียงที่สุดของจีน'),
  'yibin/firstcity': ('เมืองแรกแห่งแม่น้ำแยงซี', 'จุดที่แม่น้ำหมินเจียงและแม่น้ำจินซาไหลมาบรรจบกันจนกลายเป็นแม่น้ำแยงซี ทำให้เมืองอี๋บินได้รับสมญานามว่าเป็นเมืองแรกของแม่น้ำสายนี้'),
  'yibin/bamboosea': ('ทะเลไผ่ซู่หนาน', 'ผืนป่าไผ่ขนาดใหญ่ที่ปกคลุมภูเขากว่า 120 ลูก พลิ้วไหวราวกับคลื่นสีเขียวเมื่อต้องลม'),
  'yibin/ranmian': ('หมี่คลุกน้ำมัน', 'เมนูเส้นที่คลุกเคล้าจนแห้งและมีน้ำมันชุ่มฉ่ำจนเกือบติดไฟได้ เป็นอาหารเช้ายอดนิยมที่เผ็ดร้อนถึงใจของชาวอี๋บิน'),
  'luzhou/laojiao': ('โรงบ่มเหล้าหลูโจวเหล่าเจี้ยว', 'บ่อหมักเหล้าดินเหนียวที่ใช้งานต่อเนื่องมาตั้งแต่ปี ค.ศ. 1573 คือหัวใจสำคัญที่ทำให้เหล้าไป๋จิ่วมีกลิ่นหอมเป็นเอกลักษณ์'),
  'luzhou/port': ('ท่าเรือแม่น้ำแยงซี', 'เมืองท่าแห่งนี้ตั้งอยู่ตรงจุดบรรจบของแม่น้ำสองสาย ถือเป็นประตูทางน้ำของมณฑลเสฉวนที่เชื่อมต่อไปยังทะเล'),
  'luzhou/longan': ('สวนลำไย', 'ลำไยที่ปลูกบนเนินเขาอบอุ่นริมแม่น้ำเป็นผลไม้รสหวานฉ่ำที่คนจีนเรียกว่าผลไม้ตาของมังกร'),
  'luzhou/umbrella': ('ร่มกระดาษน้ำมัน', 'ร่มกระดาษน้ำมันทำมือจากปรมาจารย์แห่งเมืองเฟินสุ่ยเป็นงานฝีมืออันงดงามที่สืบทอดกันมากว่าสี่ร้อยปี'),
  'leshan/giantbuddha': ('พระใหญ่เล่อซาน', 'พระพุทธรูปนั่งแกะสลักหน้าผาสูง 71 เมตรองค์นี้เฝ้ามองจุดบรรจบของแม่น้ำมานานกว่าสิบสองศตวรรษ'),
  'leshan/emei': ('ภูเขาเอ๋อเหมย', 'ยอดเขาทองคำแห่งภูเขาเอ๋อเหมย หนึ่งในสี่ขุนเขาศักดิ์สิทธิ์ทางพุทธศาสนา ทอแสงประกายเหนือทะเลหมอก'),
  'leshan/monkeys': ('ลิงแสมแห่งภูเขาเอ๋อเหมย', 'ลิงแสมจอมซนตามเส้นทางบนภูเขาขึ้นชื่อเรื่องความกล้าหาญในการรื้อค้นกระเป๋าของนักท่องเที่ยว'),
  'leshan/qiaojiao': ('ซุปเนื้อเฉียวเจี่ยว', 'ซุปเนื้อตุ๋นสมุนไพรเฉียวเจี่ยวเป็นเมนูคลาสสิกอายุกว่าร้อยปีที่พบได้ตามร้านอาหารริมทางในเล่อซาน'),
  'zigong/saltwell': ('บ่อเกลือลึกหนึ่งกิโลเมตร', 'บ่อเซินไห่เป็นบ่อเกลือแห่งแรกของโลกที่ขุดลึกเกินหนึ่งพันเมตร ถือเป็นความสำเร็จอันยิ่งใหญ่ของเมืองแห่งเกลือที่มีประวัติศาสตร์ยาวนานสองพันปี'),
  'zigong/lantern': ('เทศกาลโคมไฟจื้อกง', 'สวนโคมไฟขนาดมหึมาที่ส่องสว่างไสวเปลี่ยนเมืองทั้งเมืองให้กลายเป็นดินแดนแห่งเทพนิยายในช่วงเทศกาลปีใหม่'),
  'zigong/dinosaur': ('พิพิธภัณฑ์ไดโนเสาร์', 'ฟอสซิลนับพันชิ้นที่ขุดพบจากชั้นหินยุคจูราสสิกทำให้จื้อกงกลายเป็นเมืองหลวงแห่งไดโนเสาร์ของจีน'),
  'zigong/rabbit': ('เนื้อกระต่ายเย็น', 'เมนูเนื้อกระต่ายรสเผ็ดจัดจ้านเสิร์ฟเย็นหรือเหลิ่งทู่เป็นอาหารเรียกน้ำย่อยที่โดดเด่นที่สุดของเมืองนี้'),
  'panzhihua/steel': ('เมืองหลวงแห่งแร่เหล็กและไทเทเนียม', 'เมืองอุตสาหกรรมเหล็กกล้าขนาดใหญ่ที่สร้างขึ้นท่ามกลางหุบเขาแห่งนี้เป็นแหล่งผลิตแร่เหล็กและไทเทเนียมที่อุดมสมบูรณ์ที่สุดในโลก'),
  'panzhihua/fruitvalley': ('หุบเขาผลไม้แดดจัด', 'มะม่วงและทับทิมจากหุบเขาที่แห้งแล้งและร้อนระอุแห่งนี้สามารถสุกงอมได้แม้ในช่วงฤดูหนาวเพราะได้รับแสงแดดเต็มที่'),
  'panzhihua/sunshine': ('เมืองแห่งแสงแดดฤดูหนาว', 'ด้วยปริมาณแสงแดดกว่า 2,700 ชั่วโมงต่อปี พานจือฮวาจึงเป็นจุดหมายปลายทางเพื่อสุขภาพสำหรับผู้ที่ต้องการหลบหนาวมาพักผ่อน'),
  'panzhihua/jinsha': ('แม่น้ำจินซา', 'แม่น้ำจินซาที่มีหาดทรายสีทองไหลผ่านตัวเมือง กัดเซาะจนเกิดเป็นหุบเขาลึกที่สวยงาม'),
  'dazhou/gas': ('เมืองหลวงแห่งก๊าซธรรมชาติ', 'แหล่งก๊าซผู่กวงขนาดใหญ่ทำให้เมืองต๋าโจวกลายเป็นฐานพลังงานก๊าซธรรมชาติที่สำคัญของจีน'),
  'dazhou/ba': ('มรดกอาณาจักรปา', 'ดินแดนแห่งนักรบปาโบราณผู้ใช้ดาบใบหลิว บอกเล่าเรื่องราวผ่านโบราณสถานหลัวเจียป้า'),
  'dazhou/dengying': ('เนื้อวัวเติงอิ่ง', 'เนื้อวัวแผ่นบางจนแสงส่องผ่านได้ที่ปรุงรสเผ็ดร้อนนี้ ได้ชื่อมาจากศิลปะการแสดงหุ่นเงา'),
  'dazhou/hanque': ('หอหินตระกูลฮั่น', 'หอหินโบราณอายุกว่าสองพันปีในอำเภอชวีเซี่ยน เป็นสถาปัตยกรรมสมัยราชวงศ์ฮั่นที่ยังคงหลงเหลืออยู่'),
  'guangyuan/jianmen': ('ด่านเจี้ยนเหมิน', 'ด่านขุนเขาที่ขึ้นชื่อว่าแม้คนเดียวก็สามารถต้านทานกองทัพนับหมื่นได้ เปรียบเสมือนกุญแจสำคัญของเส้นทางสู่เสฉวน'),
  'guangyuan/wuzetian': ('บ้านเกิดของบูเช็กเทียน', 'จักรพรรดินีเพียงหนึ่งเดียวของจีนประสูติที่นี่ โดยมีวัดหวงเจ๋อคอยรำลึกถึงพระองค์มานานนับพันปี'),
  'guangyuan/plankroad': ('ทางเดินไม้โบราณ', 'ทางเดินไม้ที่ตอกยึดไว้กับหน้าผาสูงชัน เป็นอนุสรณ์แห่งความกล้าหาญบนเส้นทางสู่เสฉวนที่ยากลำบากยิ่งกว่าการขึ้นสวรรค์'),
  'guangyuan/cypress': ('ระเบียงต้นสนชุ่ยหยุน', 'ต้นสนโบราณนับหมื่นต้นจากยุคสามก๊กเปลี่ยนเส้นทางสายเก่าให้กลายเป็นอุโมงค์สีเขียวขจี'),
  'yaan/panda': ('แหล่งกำเนิดหมีแพนด้า', 'หมีแพนด้ายักษ์ถูกค้นพบทางวิทยาศาสตร์ครั้งแรกที่อำเภอเป่าซิงในปี ค.ศ. 1869 และศูนย์วิจัยปี้เฟิงเสียยังคงสืบสานมรดกนั้นมาจนถึงปัจจุบัน'),
  'yaan/rain': ('เมืองแห่งสายฝน', 'สายฝนแห่งเมืองหย่าอันมักโปรยปรายลงมาในยามค่ำคืน ทำให้เมืองดูสดใสด้วยสีเขียวขจีในทุกมุมมอง'),
  'yaan/mengding': ('ชาเขาเหมิงติ่ง', 'ชาถูกปลูกโดยฝีมือมนุษย์ครั้งแรกบนเขาเหมิงติ่งเมื่อสองพันปีก่อน ที่นี่จึงถือเป็นแหล่งกำเนิดวัฒนธรรมการดื่มชา'),
  'yaan/yayu': ('ปลาหย่า', 'ปลาหย่าในตำนานจากลำธารที่ละลายจากหิมะเป็นความภาคภูมิใจของเมือง มักนำมาปรุงเป็นเมนูหม้อไฟรสเลิศ'),
  'xianyang/qincapital': ('เมืองหลวงจักรวรรดิฉิน', 'ที่นี่เคยเป็นเมืองหลวงของราชวงศ์ฉิน ผู้รวมแผ่นดินจีนเป็นหนึ่งเดียว เส้นทางสู่จักรวรรดิล้วนเริ่มต้นจากเสียนหยาง'),
  'xianyang/qianling': ('สุสานเฉียนหลิง', 'สุสานบนภูเขาที่เป็นที่ฝังพระศพของบูเช็กเทียนและพระสวามี ท้าทายประวัติศาสตร์ด้วยศิลาจารึกไร้อักษร'),
  'xianyang/zhengguo': ('คลองเจิ้งกั๋ว', 'คลองชลประทานที่มีอายุกว่าสองพันปีแห่งนี้ได้เปลี่ยนที่ราบกวนจงให้กลายเป็นอู่ข้าวอู่น้ำของรัฐฉิน'),
  'xianyang/guokui': ('ขนมปังแผ่นกั๋วขุย', 'กั๋วขุยเป็นขนมปังแผ่นกรอบที่มีขนาดใหญ่เท่าฝาหม้อ ซึ่งเป็นอาหารว่างดั้งเดิมที่อยู่คู่โต๊ะอาหารของชาวส่านซีมานานหลายศตวรรษ'),
  'baoji/bronze': ('เมืองหลวงแห่งเครื่องสัมฤทธิ์', 'เมืองเป่าจีเป็นแหล่งค้นพบเครื่องสัมฤทธิ์สมัยราชวงศ์โจวนับพันชิ้น รวมถึงเหอจุนซึ่งเป็นวัตถุโบราณชิ้นแรกที่ปรากฏคำว่า \'จงกั๋ว\' หรือประเทศจีน'),
  'baoji/famen': ('วัดฝ่าเหมิน', 'วัดฝ่าเหมินเป็นสถานที่ประดิษฐานพระบรมสารีริกธาตุส่วนพระอัฐินิ้วพระหัตถ์ของพระพุทธเจ้า และเคยเป็นคลังสมบัติอันศักดิ์สิทธิ์ของจักรพรรดิราชวงศ์ถัง'),
  'baoji/taibai': ('ภูเขาไท่ไป๋', 'ภูเขาไท่ไป๋มีความสูงถึง 3,771 เมตร ถือเป็นยอดเขาที่สูงที่สุดในเทือกเขาฉินหลิ่งและมีหิมะปกคลุมแม้ในช่วงฤดูร้อนจนกลายเป็นตำนานเล่าขาน'),
  'baoji/saozi': ('บะหมี่เซ่าจื่อ', 'บะหมี่เซ่าจื่อแห่งเมืองฉีซานที่มีรสชาติเปรี้ยวเผ็ดจากซอสเนื้อ เป็นรสชาติอาหารดั้งเดิมที่สืบทอดมาตั้งแต่สมัยราชวงศ์โจวเมื่อสามพันปีก่อน'),
};
